1	use crate::expr::{Expr, UseKind};
2	use crate::span::Span;
3	use crate::transpiler::code_gen_context::CodeGenContext;
4	use crate::transpiler::compiletime_env::CompileTimeEnv;
5	use crate::type_env::{nil_type, Type};
6	use crate::{error, STD_PATH};
7	use std::collections::HashMap;
8	use std::path::Path;
9	
10	impl Expr {
11	    pub fn to_c(&self, cte: &mut CompileTimeEnv, ctx: &mut CodeGenContext) -> bool {
12	        // if true - requires a semicolon at end of statement
13	        match self {
14	            Expr::Int(n) => {
15	                ctx.body.push_str(&n.to_string());
16	                false
17	            }
18	            Expr::Float(n) => {
19	                if n.fract() == 0.0 {
20	                    ctx.body.push_str(&n.to_string());
21	                    ctx.body.push_str(".0");
22	                } else {
23	                    ctx.body.push_str(&n.to_string());
24	                }
25	                false
26	            }
27	
28	            Expr::Bool(b) => {
29	                ctx.body.push_str(if *b { "true" } else { "false" });
30	                false
31	            }
32	            Expr::Char(c) => {
33	                ctx.body.push('\'');
34	                ctx.body.push_str(&c.to_string());
35	                ctx.body.push('\'');
36	                false
37	            }
38	            Expr::Str(s) => {
39	                ctx.body.push('"');
40	                for c in s.chars() {
41	                    match c {
42	                        '\n' => ctx.body.push_str("\\n"),
43	                        '\t' => ctx.body.push_str("\\t"),
44	                        _ => ctx.body.push(c),
45	                    }
46	                }
47	                ctx.body.push('"');
48	                false
49	            }
50	
51	            Expr::Add(l, r, span) => {
52	                Expr::CallFunc(
53	                    "_add".into(),
54	                    vec![l.get_type(cte)],
55	                    vec![l.clone(), r.clone()],
56	                    *span,
57	                )
58	                .to_c(cte, ctx);
59	                false
60	            }
61	
62	            Expr::Div(l, r, span) => {
63	                Expr::CallFunc(
64	                    "_div".into(),
65	                    vec![l.get_type(cte)],
66	                    vec![l.clone(), r.clone()],
67	                    *span,
68	                )
69	                .to_c(cte, ctx);
70	                false
71	            }
72	
73	            Expr::Less(l, r, span) => {
74	                Expr::CallFunc(
75	                    "_less".into(),
76	                    vec![l.get_type(cte)],
77	                    vec![l.clone(), r.clone()],
78	                    *span,
79	                )
80	                .to_c(cte, ctx);
81	                false
82	            }
83	
84	            Expr::Power(l, r, span) => {
85	                Expr::CallFunc(
86	                    "_pow".into(),
87	                    vec![l.get_type(cte)],
88	                    vec![l.clone(), r.clone()],
89	                    *span,
90	                )
91	                .to_c(cte, ctx);
92	                false
93	            }
94	            Expr::Sub(l, r, span) => {
95	                Expr::CallFunc(
96	                    "_sub".into(),
97	                    vec![l.get_type(cte)],
98	                    vec![l.clone(), r.clone()],
99	                    *span,
100	                )
101	                .to_c(cte, ctx);
102	                false
103	            }
104	            Expr::Mult(l, r, span) => {
105	                Expr::CallFunc(
106	                    "_mult".into(),
107	                    vec![l.get_type(cte)],
108	                    vec![l.clone(), r.clone()],
109	                    *span,
110	                )
111	                .to_c(cte, ctx);
112	                false
113	            }
114	            Expr::EqualEqual(l, r, span) => {
115	                Expr::CallFunc(
116	                    "_equal".into(),
117	                    vec![l.get_type(cte)],
118	                    vec![l.clone(), r.clone()],
119	                    *span,
120	                )
121	                .to_c(cte, ctx);
122	                false
123	            }
124	            Expr::Greater(l, r, span) => {
125	                Expr::CallFunc(
126	                    "_greater".into(),
127	                    vec![l.get_type(cte)],
128	                    vec![l.clone(), r.clone()],
129	                    *span,
130	                )
131	                .to_c(cte, ctx);
132	                false
133	            }
134	            Expr::GreaterEqual(l, r, span) => {
135	                Expr::CallFunc(
136	                    "_greater_equal".into(),
137	                    vec![l.get_type(cte)],
138	                    vec![l.clone(), r.clone()],
139	                    *span,
140	                )
141	                .to_c(cte, ctx);
142	                false
143	            }
144	
145	            Expr::LessEqual(l, r, span) => {
146	                Expr::CallFunc(
147	                    "_less_equal".into(),
148	                    vec![l.get_type(cte)],
149	                    vec![l.clone(), r.clone()],
150	                    *span,
151	                )
152	                .to_c(cte, ctx);
153	                false
154	            }
155	
156	            Expr::BangEqual(l, r, span) => {
157	                Expr::CallFunc(
158	                    "_bang_equal".into(),
159	                    vec![l.get_type(cte)],
160	                    vec![l.clone(), r.clone()],
161	                    *span,
162	                )
163	                .to_c(cte, ctx);
164	                false
165	            }
166	
167	            Expr::StmtBlock(exprs, _span) => {
168	                for expr in exprs {
169	                    if expr.to_c(cte, ctx) {
170	                        ctx.body.push(';');
171	                    }
172	                    ctx.body.push('\n');
173	                }
174	                false
175	            }
176	
177	            Expr::If(if_cond, if_block, else_block, is_expr) => {
178	                if !is_expr {
179	                    ctx.body.push_str("if (");
180	                    if_cond.to_c(cte, ctx);
181	                    ctx.body.push_str(")");
182	                    if_block.to_c(cte, ctx);
183	                    if else_block.is_some() {
184	                        ctx.body.push_str(" else ");
185	                        else_block.clone().unwrap().to_c(cte, ctx);
186	                    }
187	                } else {
188	                    error(
189	                        if_cond.get_span(),
190	                        "EXPRESSION IF STATEMENTS NOT IMPLEMENTED",
191	                        "transpiling",
192	                    );
193	                }
194	
195	                let else_type = if let Some(ty) = else_block {
196	                    ty.get_type(cte)
197	                } else {
198	                    nil_type()
199	                };
200	                if if_block.get_type(cte) != else_type {
201	                    error(
202	                        if_block.get_span(),
203	                        "if and else blocks had different types",
204	                        "transpiling",
205	                    );
206	                }
207	
208	                false
209	            }
210	
211	            Expr::StmtBlockWithScope(exprs, span) => {
212	                cte.push_scope();
213	                ctx.body.push_str("{\n");
214	                Expr::StmtBlock(exprs.clone(), *span).to_c(cte, ctx);
215	                ctx.body.push('}');
216	                cte.pop_scope();
217	                false
218	            }
219	
220	            Expr::Print(expr, span) => {
221	                Expr::CallFunc(
222	                    "_print".into(),
223	                    vec![expr.get_type(cte)],
224	                    vec![expr.clone()],
225	                    *span,
226	                )
227	                .to_c(cte, ctx);
228	                true
229	            }
230	
231	            Expr::Discard(expr) => {
232	                expr.to_c(cte, ctx);
233	                true
234	            }
235	
236	            Expr::Variable(name, span) => {
237	                ctx.body.push_str(&cte.c_var_name(name, *span));
238	                false
239	            }
240	
241	            Expr::This(span) => {
242	                ctx.body.push(' ');
243	                ctx.body.push_str(&cte.c_var_name(cte.this(), *span));
244	                ctx.body.push(' ');
245	                false
246	            }
247	
248	            Expr::Declare(name, var_type, expr, is_mutable, span) => {
249	                let var_type = if var_type.is_some() {
250	                    cte.declare_var(name.clone(), *is_mutable, var_type.clone().unwrap());
251	                    var_type.clone().unwrap()
252	                } else {
253	                    let t = expr.clone().unwrap().get_type(cte);
254	                    cte.declare_var(name.clone(), *is_mutable, t.clone());
255	                    t
256	                };
257	
258	                ctx.body += format!(
259	                    "{} {}",
260	                    cte.c_type_name(&var_type, *span),
261	                    cte.c_var_name(&name, *span),
262	                )
263	                .as_str();
264	
265	                if expr.is_some() {
266	                    ctx.body.push('=');
267	                    expr.clone().unwrap().to_c(cte, ctx);
268	                }
269	                true
270	            }
271	
272	            Expr::CallFunc(name, gens, exprs, span) => {
273	                if !cte.var_exists(name) {
274	                    error(
275	                        *span,
276	                        &format!("Function '{}' does not exist", name),
277	                        "transpiling",
278	                    );
279	                }
280	                ctx.body
281	                    .push_str(format!("{}(", cte.c_func_instance_name(name, gens, *span)).as_str());
282	                for expr in exprs {
283	                    expr.to_c(cte, ctx);
284	                    ctx.body.push(',');
285	                }
286	                if exprs.len() >= 1 {
287	                    ctx.body.pop();
288	                }
289	
290	                ctx.body.push_str(")");
291	                true
292	            }
293	
294	            Expr::Stmt(expr) => {
295	                expr.to_c(cte, ctx);
296	                true
297	            }
298	
299	            Expr::DeclareFunction(name, block, return_type, args, _gens, span) => {
300	                let mut arg_types = vec![];
301	                for arg in args {
302	                    arg_types.push(arg.1.clone());
303	                }
304	
305	                // Push scope and declare parameters BEFORE computing returned_type,
306	                // so that parameter variables are visible during type inference.
307	                cte.push_scope();
308	                for arg in args {
309	                    cte.declare_var(arg.0.clone(), false, arg.1.clone());
310	                }
311	
312	                let ret_type = block.returned_type(cte, *span);
313	                let return_type = if return_type.is_some() {
314	                    return_type.clone().unwrap()
315	                } else {
316	                    if let Some(ty) = ret_type.clone() {
317	                        ty
318	                    } else {
319	                        nil_type()
320	                    }
321	                };
322	
323	                ctx.body.push_str(
324	                    format!(
325	                        "{} {}(",
326	                        cte.c_type_name(&return_type, *span),
327	                        cte.c_func_instance_name(&name, &[], *span),
328	                    )
329	                    .as_str(),
330	                );
331	
332	                for arg in args {
333	                    ctx.body.push_str(&cte.c_type_name(&arg.1, *span));
334	                    ctx.body.push(' ');
335	                    ctx.body.push_str(&cte.c_var_name(&arg.0, *span));
336	                    ctx.body.push_str(", ");
337	                }
338	                if ctx.body.ends_with(", ") {
339	                    ctx.body.pop();
340	                    ctx.body.pop();
341	                }
342	
343	                ctx.body.push(')');
344	
345	                block.to_c(cte, ctx);
346	
347	                cte.pop_scope();
348	
349	                false
350	            }
351	
352	            Expr::Assign(left, right, span) => {
353	                match left.as_ref() {
354	                    Expr::Variable(name, _) => {
355	                        cte.push_this(name);
356	                        ctx.body.push_str(&cte.c_var_name(name, *span));
357	                        ctx.body.push('=');
358	                        right.to_c(cte, ctx);
359	                        cte.pop_this();
360	                    }
361	                    Expr::Member(var, member, span) => {
362	                        ctx.body.push_str(&cte.c_var_name(var, *span));
363	                        ctx.body.push('.');
364	                        ctx.body.push_str(
365	                            &cte.c_member_name(
366	                                &cte.get_var(var)
367	                                    .unwrap_or_else(|| {
368	                                        error(
369	                                            *span,
370	                                            &format!("Could not find variable '{}'", var),
371	                                            "transpiling",
372	                                        );
373	                                        (false, nil_type())
374	                                    })
375	                                    .1,
376	                                member,
377	                                *span,
378	                            ),
379	                        );
380	                        ctx.body.push('=');
381	                        right.to_c(cte, ctx);
382	                    }
383	                    _ => {
384	                        error(*span, "Invalid assignment target", "transpiler");
385	                    }
386	                }
387	                true
388	            }
389	
390	            Expr::Return(expr, _span) => {
391	                ctx.body.push_str("return ");
392	                expr.to_c(cte, ctx);
393	                true
394	            }
395	
396	            Expr::Delete(name) => {
397	                cte.del_var(name);
398	                false
399	            }
400	
401	            Expr::Nothing() => false,
402	
403	            Expr::While(cond, block) => {
404	                ctx.body.push_str("while (");
405	                cond.to_c(cte, ctx);
406	                ctx.body.push_str("){\n");
407	                block.to_c(cte, ctx);
408	                ctx.body.push_str("}");
409	                false
410	            }
411	
412	            Expr::Input(name) => {
413	                ctx.body.push_str("scanf(\"%d\",&");
414	                ctx.body.push_str(&cte.c_var_name(name, Span::empty()));
415	                ctx.body.push_str(")");
416	                true
417	            }
418	
419	            Expr::Use { .. } => false,
420	
421	            Expr::Class(ty, members, span) => {
422	                let c_type_name = cte.c_type_name(ty, *span);
423	                ctx.types.push_str("struct ");
424	                ctx.types.push_str(&c_type_name);
425	                ctx.types.push_str(" {\n");
426	                for member in members {
427	                    ctx.types.push_str(&cte.c_type_name(&member.1, *span));
428	                    ctx.types.push(' ');
429	                    ctx.types.push_str(&cte.c_member_name(ty, &member.0, *span));
430	                    ctx.types.push_str("; \n");
431	                }
432	                if ctx.types.ends_with("; \n") {
433	                    ctx.types.pop();
434	                    ctx.types.pop();
435	                    ctx.types.push('\n');
436	                }
437	                ctx.types.push_str("};\n");
438	
439	                true
440	            }
441	
442	            Expr::Member(variable, member, span) => {
443	                ctx.body.push_str(&cte.c_var_name(variable, *span));
444	                ctx.body.push('.');
445	
446	                let var = cte.get_var(variable);
447	                if var.is_none() {
448	                    error(
449	                        *span,
450	                        &format!("Variable '{}' not defined", variable),
451	                        "type checker",
452	                    );
453	                }
454	                let variable = var.unwrap();
455	                ctx.body
456	                    .push_str(&cte.c_member_name(&variable.1, member, *span));
457	                false
458	            }
459	
460	            _ => panic!("unexpected expression (for transpilation) '{:?}'", self),
461	        }
462	    }
463	
464	    pub fn pre_transpile(
465	        &self,
466	        cte: &mut CompileTimeEnv,
467	        ctx: &mut CodeGenContext,
468	        programs_to_transpile: &mut HashMap<String, bool>,
469	    ) {
470	        match self {
471	            Expr::DeclareFunction(name, block, return_type, args, _gens, span) => {
472	                if cte.get_var(name).is_some() {
473	                    error(
474	                    *span,
475	                    format!(
476	                        "Variable '{}' already exists and is immutable, could not declare function",
477	                        name
478	                    )
479	                        .as_str(),"pre-transpiling"
480	                );
481	                }
482	                let mut arg_types = vec![];
483	                for arg in args {
484	                    arg_types.push(arg.1.clone());
485	                }
486	
487	                // Push scope and declare parameters BEFORE computing returned_type,
488	                // so that parameter variables are visible during type inference.
489	                cte.push_scope();
490	                for arg in args {
491	                    cte.declare_var(arg.0.clone(), false, arg.1.clone());
492	                }
493	
494	                let ret_type = block.returned_type(cte, *span);
495	                let return_type = if return_type.is_some() {
496	                    return_type.clone().unwrap()
497	                } else {
498	                    if let Some(ty) = ret_type.clone() {
499	                        ty
500	                    } else {
501	                        nil_type()
502	                    }
503	                };
504	
505	                cte.add_func_type(return_type.clone(), arg_types.clone(), ctx, *span);
506	                // Declare the variable first so c_func_instance_name can find it
507	                cte.declare_global_var(
508	                    name.clone(),
509	                    false,
510	                    Type::with_generics("func", {
511	                        arg_types.push(return_type.clone());
512	                        let output = arg_types;
513	                        output
514	                    }),
515	                );
516	
517	                ctx.declarations.push_str(
518	                    format!(
519	                        "{} {}(",
520	                        cte.c_type_name(&return_type, *span),
521	                        cte.c_func_instance_name(&name, &[], *span),
522	                    )
523	                    .as_str(),
524	                );
525	
526	                for arg in args {
527	                    ctx.declarations.push_str(&cte.c_type_name(&arg.1, *span));
528	                    ctx.declarations.push(' ');
529	                    ctx.declarations.push_str(&cte.c_var_name(&arg.0, *span));
530	                    ctx.declarations.push_str(", ");
531	                }
532	                if ctx.declarations.ends_with(", ") {
533	                    ctx.declarations.pop();
534	                    ctx.declarations.pop();
535	                }
536	
537	                ctx.declarations.push_str(");\n");
538	
539	                block.pre_transpile(cte, ctx, programs_to_transpile);
540	
541	                cte.pop_scope();
542	            }
543	            Expr::Use { kind, path, span } => {
544	                let crate_path = match kind {
545	                    UseKind::Std => STD_PATH,
546	                    UseKind::Normal => "",
547	                };
548	
549	                let full_path = format!("{}{}", crate_path, path);
550	
551	                if !Path::new(&full_path).exists() {
552	                    error(*span, "File does not exist!", "pre-transpiling");
553	                }
554	
555	                if !programs_to_transpile.contains_key(&full_path) {
556	                    programs_to_transpile.insert(full_path, false);
557	                }
558	            }
559	
560	            Expr::StmtBlock(exprs, _) | Expr::StmtBlockWithScope(exprs, _) => {
561	                for expr in exprs {
562	                    expr.pre_transpile(cte, ctx, programs_to_transpile);
563	                }
564	            }
565	
566	            Expr::Discard(expr) => expr.pre_transpile(cte, ctx, programs_to_transpile),
567	
568	            Expr::Class(ty, members, span) => {
569	                cte.register_class(ty.clone());
570	
571	                for member in members {
572	                    cte.declare_member(member.0.clone(), member.1.clone(), ty.clone());
573	                }
574	
575	                let c_type_name = cte.c_type_name(ty, *span);
576	                ctx.include.push_str("struct ");
577	                ctx.include.push_str(&c_type_name);
578	                ctx.include.push_str(";\n");
579	
580	                ctx.types.push_str("\ntypedef struct ");
581	                ctx.types.push_str(&c_type_name);
582	                ctx.types.push(' ');
583	                ctx.types.push_str(&c_type_name);
584	                ctx.types.push_str(";\n");
585	            }
586	
587	            Expr::Declare(name, var_type, expr, is_mutable, _span) => {
588	                if let Some(var_type) = var_type {
589	                    cte.declare_var(name.clone(), *is_mutable, var_type.clone());
590	                } else if let Some(expr_box) = expr {
591	                    let t = expr_box.get_type(cte);
592	                    cte.declare_var(name.clone(), *is_mutable, t);
593	                }
594	                if let Some(expr_box) = expr {
595	                    expr_box.pre_transpile(cte, ctx, programs_to_transpile);
596	                }
597	            }
598	
599	            _ => {}
600	        }
601	    }
