603	    fn get_type(&self, cte: &CompileTimeEnv) -> Type {
604	        match self {
605	            Expr::Int(_) => "i32".into(),
606	            Expr::Float(_) => "f64".into(),
607	            Expr::Str(_) => "strlit".into(),
608	            Expr::Bool(_)
609	            | Expr::EqualEqual(..)
610	            | Expr::BangEqual(..)
611	            | Expr::Less(..)
612	            | Expr::LessEqual(..)
613	            | Expr::Greater(..)
614	            | Expr::GreaterEqual(..) => "bool".into(),
615	            Expr::Char(_) => "char".into(),
616	            Expr::Add(l, _, _)
617	            | Expr::Sub(l, ..)
618	            | Expr::Mult(l, ..)
619	            | Expr::Power(l, ..)
620	            | Expr::Div(l, ..) => l.get_type(cte),
621	            Expr::Return(_, _span) => nil_type(),
622	            Expr::CallFunc(name, _, _, span) => {
623	                let function = cte
624	                    .get_var(name)
625	                    .unwrap_or_else(|| {
626	                        error(
627	                            *span,
628	                            &format!("Function not defined: {}", name),
629	                            "type checker",
630	                        );
631	                        (false, nil_type())
632	                    })
633	                    .1;
634	                function.generics()[0].clone()
635	            }
636	            Expr::StmtBlock(exprs, _span) => exprs.last().unwrap().get_type(cte),
637	            Expr::StmtBlockWithScope(exprs, _span) => exprs.last().unwrap().get_type(cte),
638	            Expr::Variable(name, span) => {
639	                cte.get_var(name)
640	                    .unwrap_or_else(|| {
641	                        error(
642	                            *span,
643	                            &format!("Variable not defined: {}", name),
644	                            "type checker",
645	                        );
646	                        (false, nil_type())
647	                    })
648	                    .1
649	            }
650	            Expr::Discard(..) => nil_type(),
651	            Expr::Print(expr, _) => expr.get_type(cte),
652	            Expr::If(_, block, ..) => block.get_type(cte),
653	            Expr::Member(variable, member_name, span) => {
654	                let var = cte.get_var(variable);
655	                if var.is_none() {
656	                    error(
657	                        *span,
658	                        &format!("Variable '{}' not defined", variable),
659	                        "type checker",
660	                    );
661	                }
662	                let variable = var.unwrap();
663	                let var_type = variable.1;
664	
665	                let member = cte.get_member_type(&var_type, member_name);
666	
667	                let member_type = if member.is_none() {
668	                    error(
669	                        *span,
670	                        &format!(
671	                            "Member '{}' not defined for type '{}'",
672	                            member_name, var_type
673	                        ),
674	                        "type checker",
675	                    );
676	                    nil_type()
677	                } else {
678	                    member.unwrap()
679	                };
680	
681	                member_type
682	            }
