284	    // Scope Management
285	
286	    pub fn push_scope(&mut self) {
287	        self.scopes.push(HashMap::new());
288	        self.current_scope += 1;
289	    }
290	
291	    pub fn pop_scope(&mut self) {
292	        self.scopes.pop();
293	        self.current_scope -= 1;
294	    }
295	
296	    // Class handling
297	
298	    pub fn declare_member(&mut self, name: String, t: Type, class_type: Type) -> usize {
299	        let class = self.members.get_mut(&class_type).unwrap();
300	        let id = class.1;
301	
302	        class.0.push((name, t));
303	
304	        id
305	    }
306	
307	    pub fn c_member_name(&mut self, ty: &Type, name: &str, span: Span) -> String {
308	        let class = self.members.get(ty);
309	
310	        match class {
311	            Some(class) => {
312	                format!("m_{}", class.1)
313	            }
314	            None => {
315	                error(
316	                    span,
317	                    &format!(
318	                        "Could not find type '{}' when fetching member '{}'.",
319	                        ty, name
320	                    ),
321	                    "fetching mangled member name",
322	                );
323	                String::new()
324	            }
325	        }
326	    }
327	
328	    pub fn get_member_type(&self, ty: &Type, name: &str) -> Option<Type> {
329	        let class = self.members.get(ty);
330	        match class {
331	            Some(class) => {
332	                let mut output = None;
333	                for member in class.0.iter() {
334	                    if member.0 == name {
335	                        output = Some(member.1.clone());
336	                        break;
337	                    }
338	                }
339	                output
340	            }
341	            None => None,
342	        }
343	    }
344	
345	    pub fn register_class(&mut self, ty: Type) -> usize {
346	        self.members.insert(ty.clone(), (vec![], 0));
347	        self.register_type(ty.clone())
348	    }
349	
350	    // Variable Handling
351	
352	    pub fn declare_var(&mut self, name: String, is_mutable: bool, var_type: Type) -> usize {
353	        let id = self.next_var_id;
354	        self.next_var_id += 1;
355	
356	        let scope = self.scopes.last_mut().unwrap();
357	        scope.insert(name, (id, is_mutable, var_type));
358	
359	        id
360	    }
361	
362	    pub fn declare_global_var(&mut self, name: String, is_mutable: bool, var_type: Type) -> usize {
363	        let id = self.next_var_id;
364	        self.next_var_id += 1;
365	
366	        let scope = self.scopes.first_mut().unwrap();
367	        scope.insert(name, (id, is_mutable, var_type));
368	
369	        id
370	    }
371	
372	    fn resolve_var(&self, name: &str) -> Option<(usize, usize)> {
373	        for (idx, scope) in self.scopes.iter().enumerate().rev() {
374	            if let Some(id) = scope.get(name) {
375	                return Some((id.0, idx));
376	            }
377	        }
378	        None
379	    }
380	
381	    pub fn get_var(&self, name: &str) -> Option<(bool, Type)> {
382	        for scope in self.scopes.iter().rev() {
383	            if let Some((_id, is_mutable, var_type)) = scope.get(name) {
384	                return Some((*is_mutable, var_type.clone()));
385	            }
386	        }
387	        None
388	    }
389	
390	    pub fn var_exists(&self, name: &str) -> bool {
391	        for scope in self.scopes.iter().rev() {
392	            if let Some(_) = scope.get(name) {
393	                return true;
394	            }
395	        }
396	        false
397	    }
398	
399	    /// Returns the C variable name for variables.\
400	    /// Format: v_{id}s_{scope}
401	    pub fn c_var_name(&self, name: &str, span: Span) -> String {
402	        let (id, scope) = self.resolve_var(name).unwrap_or_else(|| {
403	            error(
404	                span,
405	                format!("Could not find variable '{}'", name).as_str(),
406	                "fetching variable name",
407	            );
408	            (0, 0)
409	        });
410	        format!("v_{}s_{}", id, scope)
411	    }
412	
413	    /// Returns the C variable name for a function instance with generics.\
414	    /// Format: v_{id}s_{scope}C{generic_types}D for generic functions, v_{id}s_{scope}CD for non-generic
415	    pub fn c_func_instance_name(&mut self, name: &str, generics: &[Type], span: Span) -> String {
416	        let (id, scope) = self.resolve_var(name).unwrap_or_else(|| {
417	            error(
418	                span,
419	                format!("Could not find variable '{}'", name).as_str(),
420	                "fetching function name",
421	            );
422	            (0, 0)
423	        });
424	
425	        let mut result = format!("v_{}s_{}", id, scope);
426	
427	        if generics.is_empty() {
428	            // Non-generic function: add CD suffix
429	            result.push_str("CD");
430	        } else {
431	            // Generic function: add C{generics}D
432	            result.push('C');
433	            for (i, g) in generics.iter().enumerate() {
434	                result.push_str(&self.c_type_name(g, span));
435	                if i != generics.len() - 1 {
436	                    result.push('_');
437	                }
438	            }
439	            result.push('D');
440	        }
441	
442	        result
443	    }
444	
445	    // Type Handling
446	
447	    pub fn register_type(&mut self, ty: Type) -> usize {
448	        if let Type::Conceptual(name) = &ty {
449	            panic!("Tried to register conceptual type: {}", name);
450	        }
451	
452	        let canonical_ty = self.canonicalize_type(ty);
453	
454	        if let Some(index) = self.all_types.iter().position(|t| t == &canonical_ty) {
455	            return index;
456	        }
457	
458	        let id = self.next_type_id;
459	        self.next_type_id += 1;
460	
461	        self.all_types.push(canonical_ty);
462	        id
463	    }
464	
465	    /// Returns the position of a type. Does not check if the type is generic
466	    fn get_simple_type_id(&self, name: &str) -> usize {
467	        if let Some(index) = self.all_types.iter().position(|t| t.name() == name) {
468	            return index;
469	        }
470	
471	        0
472	    }
473	    /// Returns the ID of a type. If the type is generic, it registers its generic types
474	    fn get_type_id(&mut self, ty: &Type) -> Option<usize> {
475	        let canonical = self.canonicalize_type(ty.clone());
476	        self.all_types.iter().position(|t| t == &canonical)
477	    }
478	
479	    /// Registers the generic types in a generic type
480	    fn canonicalize_type(&mut self, ty: Type) -> Type {
481	        let canonical_generics: Vec<Type> = ty
482	            .generics()
483	            .iter()
484	            .map(|g| {
485	                let id = self.register_type(g.clone());
486	                self.all_types[id].clone()
487	            })
488	            .collect();
489	
490	        if canonical_generics.is_empty() {
491	            ty
492	        } else {
493	            Type::with_generics(ty.name(), canonical_generics)
494	        }
495	    }
496	
497	    /// Internal helper that generates the type name without the CD suffix
498	    fn c_type_name_raw(&mut self, ty: &Type, span: Span) -> String {
499	        // Check if this is a function type (has "func" as its name)
500	        if ty.name() == "func" {
501	            // For function types, use the mangled format: t_5C{param_types,return_type}D
502	            let gens = ty.generics();
503	            let mut name = String::from("t_5C");
504	
505	            // Add all generics (args + return type) separated by underscore
506	            for (i, g) in gens.iter().enumerate() {
507	                name.push_str(&self.c_type_name_raw(g, span));
508	                if i != gens.len() - 1 {
509	                    name.push('_');
510	                }
511	            }
512	
513	            // Close with D
514	            name.push('D');
515	
516	            name
517	        } else {
518	            // For non-function types, use the standard ID-based naming
519	            let type_id = self.get_type_id(ty).unwrap_or_else(|| {
520	                error(
521	                    span,
522	                    format!("Could not find type '{}'", ty).as_str(),
523	                    "transpiling",
524	                );
525	                0
526	            });
527	
528	            format!("t_{}", type_id)
529	        }
530	    }
531	
532	    /// Public API: returns type name with CD suffix for non-generic consistency.\
533	    /// For function types, the mangling already ends with D, so no additional CD.\
534	    /// For non-function types, add CD suffix.\
535	    /// \
536	    /// Format for simple types: t_{id}\
537	    /// Format for generic types and for simple functions: t_{id}C{generic types}D\
538	    /// Format for generic functions: t_{id}C{argument types, return type}DC{generic types}D\
539	    /// ^^^Note that generic types, argument types and return type are separated by "_".
540	    pub fn c_type_name(&mut self, ty: &Type, span: Span) -> String {
541	        let name = self.c_type_name_raw(ty, span);
542	
543	        // For function types, the raw name already ends with D, so don't add CD
544	        if ty.name() == "func" {
545	            name
546	        } else {
547	            // For non-function types, add CD suffix for consistency
548	            let mut result = name;
549	            result.push_str("CD");
550	            result
551	        }
552	    }
553	
554	    pub fn add_func_type(
555	        &mut self,
556	        ret_type: Type,
557	        arg_types: Vec<Type>,
558	        ctx: &mut CodeGenContext,
559	        span: Span,
560	    ) {
561	        // Generate the function type name using the mangling scheme
562	        // Format: t_5C{args, ret}DC{gens}D
563	        let mut gens = arg_types.clone();
564	        gens.push(ret_type.clone());
565	        let func_type = Type::with_generics("func", gens);
566	
567	        if self.get_type_id(&func_type).is_some() {
568	            return;
569	        }
570	
571	        self.register_type(func_type.clone());
572	
573	        let func_type_name = self.c_type_name(&func_type, span);
574	
575	        // Generate the typedef for the function type
576	        ctx.types.push_str("typedef ");
577	        ctx.types.push_str(&self.c_type_name(&ret_type, span));
578	        ctx.types.push_str(&format!("(*{})", func_type_name));
579	        ctx.types.push('(');
580	        for ty in arg_types.iter() {
581	            ctx.types.push_str(&self.c_type_name(&ty, span));
582	            ctx.types.push(',');
583	        }
584	        if arg_types.len() >= 1 {
585	            ctx.types.pop();
586	        }
587	        ctx.types.push_str(");\n");
588	    }
589	
590	    pub fn push_this(&mut self, this: &str) {
591	        self.these.push(this.to_string());
592	    }
593	    pub fn pop_this(&mut self) {
594	        self.these.pop();
595	    }
596	    pub fn this(&self) -> &str {
597	        &self.these.last().unwrap()
598	    }
599	
600	    pub fn del_var(&mut self, name: &str) {
601	        for scope in self.scopes.iter_mut().rev() {
602	            if let Some(_id) = scope.get(name) {
603	                scope.remove(name);
604	            }
605	        }
606	    }
607	
608	    pub fn complete(&mut self, _ctx: &mut CodeGenContext) {
609	        todo!("This function is currently not implemented");
610	    }
611	}
