6	
7	pub struct Parser<'a> {
8	    tokens: &'a [Token],
9	    current: usize,
10	}
11	
12	impl<'a> Parser<'a> {
13	    pub fn new(tokens: &'a [Token]) -> Self {
14	        Self { tokens, current: 0 }
15	    }
16	
17	    // ---------- ENTRY ----------
18	    pub fn parse(&mut self) -> Expr {
19	        let mut statements = Vec::new();
20	
21	        while !self.is_at_end() {
22	            statements.push(Box::new(self.statement()));
23	            if !self.match_any(&[TokenType::Semicolon]) && !self.is_at_end() {
24	                let t = self.peek();
25	                error(
26	                    self.get_span(),
27	                    format!("Expected ';' after statement. Found '{}'", t.token_type).as_str(),
28	                    "parsing",
29	                );
30	                self.advance();
31	            }
32	        }
33	
34	        Expr::StmtBlock(statements, self.get_span())
35	    }
36	
37	    // ---------- STATEMENTS ----------
38	    fn statement(&mut self) -> Expr {
39	        if self.match_any(&[TokenType::Dollar]) {
40	            return self.print();
41	        }
42	
43	        if self.match_any(&[TokenType::Ret]) {
44	            return self.return_stmt();
45	        }
46	
47	        if self.match_any(&[Pound]) {
48	            return self.while_loop();
49	        }
50	
51	        if self.match_any(&[TokenType::Fn]) {
52	            return self.define_function();
53	        }
54	
55	        if self.match_any(&[TokenType::Hash]) {
56	            return self.declaration();
57	        }
58	
59	        if self.match_any(&[TokenType::Del]) {
60	            return self.delete();
61	        }
62	
63	        if self.match_any(&[TokenType::QuestionMark]) {
64	            return self.if_statement(false);
65	        }
66	
67	        if self.match_any(&[TokenType::Use]) {
68	            return self.use_file();
69	        }
70	
71	        if self.match_any(&[TokenType::For]) {
72	            return self.for_loop();
73	        }
74	
75	        if self.match_any(&[TokenType::Cls]) {
76	            return self.class();
77	        }
78	
79	        Expr::Stmt(Box::new(self.expression()))
80	    }
81	
82	    // ---------- USE ------------
83	
84	    fn use_file(&mut self) -> Expr {
85	        let kind = if self.match_any(&[TokenType::Std]) {
86	            UseKind::Std
87	        } else {
88	            UseKind::Normal
89	        };
90	        self.consume(TokenType::String, "Expected file name after 'use' keyword");
91	        Expr::Use {
92	            kind,
93	            path: self.previous().literal,
94	            span: self.get_span(),
95	        }
96	    }
97	
98	    // ---------- BLOCK ----------
99	    fn statement_block(&mut self) -> Expr {
100	        let mut statements = Vec::new();
101	
102	        while !self.check(TokenType::RightBrace) && !self.is_at_end() {
103	            let statement = self.statement();
104	
105	            if !self.check(TokenType::Semicolon) && !self.check(TokenType::RightBrace) {
106	                let t = self.peek();
107	                error(
108	                    self.get_span(),
109	                    format!("Expected ';' after statement. Found '{}'", t.token_type).as_str(),
110	                    "parsing",
111	                );
112	                self.advance();
113	            }
114	            if self.match_any(&[TokenType::Semicolon]) {
115	                statements.push(Box::new(Expr::Discard(Box::new(statement))));
116	            } else {
117	                statements.push(Box::new(statement));
118	            }
119	        }
120	
121	        self.consume(TokenType::RightBrace, "Expected '}' after block.");
122	        Expr::StmtBlockWithScope(statements, self.get_span())
123	    }
124	
125	    // ---------- DELETE VAR -----------
126	
127	    fn delete(&mut self) -> Expr {
128	        if self.match_any(&[TokenType::Ident]) {
129	            Expr::Delete(self.previous().lexeme)
130	        } else {
131	            error(
132	                self.get_span(),
133	                "Expected variable name after 'del'.",
134	                "parsing",
135	            );
136	            Expr::Nothing()
137	        }
138	    }
139	
140	    // ---------- NEW CLASS -----------
141	
142	    fn class(&mut self) -> Expr {
143	        self.consume(TokenType::Ident, "Expected class name after 'cls'.");
144	        let name = self.previous().lexeme;
145	        self.consume(TokenType::LeftBrace, "Expected '{' after class name");
146	
147	        let mut members = Vec::new();
148	
149	        while !self.match_any(&[TokenType::RightBrace]) {
150	            self.consume(
151	                TokenType::Ident,
152	                "Expected an identifier at start of line (in class declaration)",
153	            );
154	            let name = self.previous().lexeme;
155	            self.consume(
156	                TokenType::Colon,
157	                "Expected colon after identifier in class declaration",
158	            );
159	
160	            members.push((name, self.get_type()));
161	        }
162	
163	        let class_type = Type::simple(&name);
164	
165	        Expr::Class(class_type, members, self.get_span())
166	    }
167	    // ---------- MEMBER VARIABLE -----------
168	
169	    fn member(&mut self, variable: String) -> Expr {
170	        let member = self.ident();
171	
172	        Expr::Member(variable, member, self.get_span())
173	    }
