175	    // ---------- WHILE LOOP -----------
176	
177	    fn while_loop(&mut self) -> Expr {
178	        let cond = self.expression();
179	        // self.current += 1;
180	        let block = if self.match_any(&[TokenType::LeftBrace]) {
181	            self.statement_block()
182	        } else {
183	            error(
184	                self.get_span(),
185	                ("Expected '{' after 'while' condition, found '".to_string()
186	                    + self.previous().lexeme.as_str()
187	                    + "'")
188	                    .as_str(),
189	                "parsing",
190	            );
191	            Expr::Nothing()
192	        };
193	
194	        Expr::While(Box::new(cond), Box::new(block))
195	    }
