10	/// Helper to transpile source to C code
11	fn transpile_to_c(source: &str) -> String {
12	    let mut scanner = Scanner::new(source.to_string());
13	    let tokens = scanner.scan_tokens();
14	    let mut parser = Parser::new(tokens);
15	    let expr = parser.parse();
16	
17	    let mut ctx = CodeGenContext::new();
18	    let mut cte = CompileTimeEnv::new(&mut ctx);
19	
20	    expr.pre_transpile(&mut cte, &mut ctx, &mut HashMap::new());
21	    expr.to_c(&mut cte, &mut ctx);
22	    ctx.combine(&mut cte)
23	}
