fn declare_locals_from_block(cte: &mut CompileTimeEnv, block: &Expr) {
    match block {
        Expr::StmtBlock(exprs, _) | Expr::StmtBlockWithScope(exprs, _) => {
            for expr in exprs {
                match expr.as_ref() {
