179	                    *span,
180	                )
181	                .to_c(cte, ctx);
182	                false
183	            }
184	
185	            Expr::BangEqual(l, r, span) => {
186	                Expr::CallFunc(
187	                    "_bang_equal".into(),
188	                    vec![l.get_type(cte)],
189	                    vec![l.clone(), r.clone()],
190	                    *span,
191	                )
192	                .to_c(cte, ctx);
193	                false
194	            }
195	
196	            Expr::StmtBlock(exprs, _span) => {
197	                for expr in exprs {
198	                    if expr.to_c(cte, ctx) {
199	                        ctx.body.push(';');
200	                    }
201	                    ctx.body.push('\n');
202	                }
203	                false
204	            }
205	
206	            Expr::If(if_cond, if_block, else_block, is_expr) => {
207	                if !is_expr {
208	                    ctx.body.push_str("if (");
209	                    if_cond.to_c(cte, ctx);
210	                    ctx.body.push_str(")");
211	                    if_block.to_c(cte, ctx);
212	                    if else_block.is_some() {
213	                        ctx.body.push_str(" else ");
214	                        else_block.clone().unwrap().to_c(cte, ctx);
215	                    }
216	                } else {
217	                    error(
218	                        if_cond.get_span(),
219	                        "EXPRESSION IF STATEMENTS NOT IMPLEMENTED",
220	                        "transpiling",
221	                    );
222	                }
223	
224	                let else_type = if let Some(ty) = else_block {
225	                    ty.get_type(cte)
226	                } else {
227	                    nil_type()
228	                };
229	                if if_block.get_type(cte) != else_type {
230	                    error(
231	                        if_block.get_span(),
232	                        "if and else blocks had different types",
233	                        "transpiling",
234	                    );
235	                }
236	
237	                false
238	            }
239	
240	            Expr::StmtBlockWithScope(exprs, span) => {
241	                cte.push_scope();
242	                ctx.body.push_str("{\n");
243	                Expr::StmtBlock(exprs.clone(), *span).to_c(cte, ctx);
244	                ctx.body.push('}');
245	                cte.pop_scope();
246	                false
247	            }
248	
249	            Expr::Print(expr, span) => {
250	                Expr::CallFunc(
251	                    "_print".into(),
252	                    vec![expr.get_type(cte)],
253	                    vec![expr.clone()],
254	                    *span,
255	                )
256	                .to_c(cte, ctx);
257	                true
258	            }
259	
260	            Expr::Discard(expr) => {
261	                expr.to_c(cte, ctx);
262	                true
263	            }
264	
265	            Expr::Variable(name, span) => {
266	                ctx.body.push_str(&cte.c_var_name(name, *span));
267	                false
268	            }
269	
270	            Expr::This(span) => {
271	                ctx.body.push(' ');
272	                ctx.body.push_str(&cte.c_var_name(cte.this(), *span));
273	                ctx.body.push(' ');
274	                false
275	            }
276	
277	            Expr::Declare(name, var_type, expr, is_mutable, span) => {
278	                let var_type = if var_type.is_some() {
279	                    cte.declare_var(name.clone(), *is_mutable, var_type.clone().unwrap());
280	                    var_type.clone().unwrap()
281	                } else {
282	                    let t = expr.clone().unwrap().get_type(cte);
283	                    cte.declare_var(name.clone(), *is_mutable, t.clone());
284	                    t
285	                };
286	
287	                ctx.body += format!(
288	                    "{} {}",
289	                    cte.c_type_name(&var_type, *span),
290	                    cte.c_var_name(&name, *span),
291	                )
292	                .as_str();
293	
294	                if expr.is_some() {
295	                    ctx.body.push('=');
296	                    expr.clone().unwrap().to_c(cte, ctx);
297	                }
298	                true
299	            }
300	
301	            Expr::CallFunc(name, gens, exprs, span) => {
302	                if !cte.var_exists(name) {
303	                    error(
304	                        *span,
305	                        &format!("Function '{}' does not exist", name),
306	                        "transpiling",
307	                    );
308	                }
309	                ctx.body
310	                    .push_str(format!("{}(", cte.c_func_instance_name(name, gens, *span)).as_str());
311	                for expr in exprs {
312	                    expr.to_c(cte, ctx);
313	                    ctx.body.push(',');
314	                }
315	                if exprs.len() >= 1 {
316	                    ctx.body.pop();
317	                }
318	
319	                ctx.body.push_str(")");
320	                true
321	            }
322	
323	            Expr::Stmt(expr) => {
324	                expr.to_c(cte, ctx);
325	                true
326	            }
327	
328	            Expr::DeclareFunction(name, block, return_type, args, _gens, span) => {
329	                let mut arg_types = vec![];
330	                for arg in args {
331	                    arg_types.push(arg.1.clone());
332	                }
333	
334	                // Push scope and declare parameters.
335	                cte.push_scope();
336	                for arg in args {
337	                    cte.declare_var(arg.0.clone(), false, arg.1.clone());
338	                }
339	
340	               // Infer return type from return statements in the body.
341	                // Parameters are already declared in scope. We also need to declare
342	                // local variables from the body so they're resolvable.
343	                eprintln!("TO_C DeclareFunction: block type={:?}", block);
344	                declare_locals_from_block(cte, block);
345	                eprintln!("TO_C after declare_locals");
346	
347	                let ret_type = block.returned_type(cte, *span);
348	                let return_type = if return_type.is_some() {
349	                    return_type.clone().unwrap()
350	                } else {
351	                    if let Some(ty) = ret_type.clone() {
352	                        ty
353	                    } else {
354	                        nil_type()
355	                    }
356	                };
357	
358	                ctx.body.push_str(
359	                    format!(
360	                        "{} {}(",
361	                        cte.c_type_name(&return_type, *span),
362	                        cte.c_func_instance_name(&name, &[], *span),
363	                    )
364	                    .as_str(),
365	                );
366	
367	                for arg in args {
368	                    ctx.body.push_str(&cte.c_type_name(&arg.1, *span));
369	                    ctx.body.push(' ');
370	                    ctx.body.push_str(&cte.c_var_name(&arg.0, *span));
371	                    ctx.body.push_str(", ");
372	                }
373	                if ctx.body.ends_with(", ") {
374	                    ctx.body.pop();
375	                    ctx.body.pop();
376	                }
377	
378	                ctx.body.push(')');
379	
380	                block.to_c(cte, ctx);
381	
382	                cte.pop_scope();
383	
384	                false
385	            }
386	
387	            Expr::Assign(left, right, span) => {
388	                match left.as_ref() {
389	                    Expr::Variable(name, _) => {
390	                        cte.push_this(name);
391	                        ctx.body.push_str(&cte.c_var_name(name, *span));
392	                        ctx.body.push('=');
393	                        right.to_c(cte, ctx);
394	                        cte.pop_this();
395	                    }
396	                    Expr::Member(var, member, span) => {
397	                        ctx.body.push_str(&cte.c_var_name(var, *span));
398	                        ctx.body.push('.');
399	                        ctx.body.push_str(
400	                            &cte.c_member_name(
401	                                &cte.get_var(var)
402	                                    .unwrap_or_else(|| {
403	                                        error(
404	                                            *span,
405	                                            &format!("Could not find variable '{}'", var),
406	                                            "transpiling",
407	                                        );
408	                                        (false, nil_type())
409	                                    })
410	                                    .1,
411	                                member,
412	                                *span,
413	                            ),
414	                        );
415	                        ctx.body.push('=');
416	                        right.to_c(cte, ctx);
417	                    }
418	                    _ => {
419	                        error(*span, "Invalid assignment target", "transpiler");
420	                    }
421	                }
422	                true
423	            }
424	
425	            Expr::Return(expr, _span) => {
426	                ctx.body.push_str("return ");
427	                expr.to_c(cte, ctx);
428	                true
429	            }
430	
431	            Expr::Delete(name) => {
432	                cte.del_var(name);
433	                false
434	            }
435	
436	            Expr::Nothing() => false,
437	
438	            Expr::While(cond, block) => {
439	                ctx.body.push_str("while (");
440	                cond.to_c(cte, ctx);
441	                ctx.body.push_str("){\n");
442	                block.to_c(cte, ctx);
443	                ctx.body.push_str("}");
444	                false
445	            }
446	
447	            Expr::Input(name) => {
448	                ctx.body.push_str("scanf(\"%d\",&");
449	                ctx.body.push_str(&cte.c_var_name(name, Span::empty()));
450	                ctx.body.push_str(")");
451	                true
452	            }
453	
454	            Expr::Use { .. } => false,
455	
456	            Expr::Class(ty, members, span) => {
457	                let c_type_name = cte.c_type_name(ty, *span);
458	                ctx.types.push_str("struct ");
459	                ctx.types.push_str(&c_type_name);
460	                ctx.types.push_str(" {\n");
461	                for member in members {
462	                    ctx.types.push_str(&cte.c_type_name(&member.1, *span));
463	                    ctx.types.push(' ');
464	                    ctx.types.push_str(&cte.c_member_name(ty, &member.0, *span));
465	                    ctx.types.push_str("; \n");
466	                }
467	                if ctx.types.ends_with("; \n") {
468	                    ctx.types.pop();
469	                    ctx.types.pop();
470	                    ctx.types.push('\n');
471	                }
472	                ctx.types.push_str("};\n");
473	
474	                true
475	            }
476	
477	            Expr::Member(variable, member, span) => {
478	                ctx.body.push_str(&cte.c_var_name(variable, *span));
479	                ctx.body.push('.');
480	
481	                let var = cte.get_var(variable);
482	                if var.is_none() {
483	                    error(
484	                        *span,
485	                        &format!("Variable '{}' not defined", variable),
486	                        "type checker",
487	                    );
488	                }
489	                let variable = var.unwrap();
490	                ctx.body
491	                    .push_str(&cte.c_member_name(&variable.1, member, *span));
492	                false
493	            }
494	
495	            _ => panic!("unexpected expression (for transpilation) '{:?}'", self),
496	        }
497	    }
498	
499	    pub fn pre_transpile(
500	        &self,
501	        cte: &mut CompileTimeEnv,
502	        ctx: &mut CodeGenContext,
503	        programs_to_transpile: &mut HashMap<String, bool>,
504	        current_file_dir: &str,
505	    ) {
506	        match self {
507	            Expr::DeclareFunction(name, block, return_type, args, _gens, span) => {
508	                if cte.get_var(name).is_some() {
509	                    error(
510	                    *span,
511	                    format!(
512	                        "Variable '{}' already exists and is immutable, could not declare function",
513	                        name
514	                    )
515	                        .as_str(),"pre-transpiling"
516	                );
517	                }
518	                let mut arg_types = vec![];
519	                for arg in args {
520	                    arg_types.push(arg.1.clone());
521	                }
522	
523	                // Push scope and declare parameters.
524	                cte.push_scope();
525	                for arg in args {
526	                    cte.declare_var(arg.0.clone(), false, arg.1.clone());
527	                }
528	
529	                // Process the body first so local variable declarations (like #x = ...)
530	                // are registered in the scope. This makes them visible to returned_type()
531	                // and get_type() calls that resolve variable names.
532	                block.pre_transpile(cte, ctx, programs_to_transpile, current_file_dir);
533	
534	                let ret_type = block.returned_type(cte, *span);
535	                let return_type = if return_type.is_some() {
536	                    return_type.clone().unwrap()
537	                } else {
538	                    if let Some(ty) = ret_type.clone() {
539	                        ty
540	                    } else {
541	                        nil_type()
542	                    }
543	                };
544	
545	                cte.add_func_type(return_type.clone(), arg_types.clone(), ctx, *span);
546	                // Declare the variable first so c_func_instance_name can find it
547	                cte.declare_global_var(
548	                    name.clone(),
549	                    false,
550	                    Type::with_generics("func", {
551	                        arg_types.push(return_type.clone());
552	                        let output = arg_types;
553	                        output
554	                    }),
555	                );
556	
557	                ctx.declarations.push_str(
558	                    format!(
559	                        "{} {}(",
560	                        cte.c_type_name(&return_type, *span),
561	                        cte.c_func_instance_name(&name, &[], *span),
562	                    )
563	                    .as_str(),
564	                );
565	
566	                for arg in args {
567	                    ctx.declarations.push_str(&cte.c_type_name(&arg.1, *span));
568	                    ctx.declarations.push(' ');
569	                    ctx.declarations.push_str(&cte.c_var_name(&arg.0, *span));
570	                    ctx.declarations.push_str(", ");
571	                }
572	                if ctx.declarations.ends_with(", ") {
573	                    ctx.declarations.pop();
574	                    ctx.declarations.pop();
575	                }
576	
577	                ctx.declarations.push_str(");\n");
578	
579	                cte.pop_scope();
580	            }
581	            Expr::Use { kind, path, span } => {
582	                let full_path = match kind {
583	                    UseKind::Std => format!("{}{}", STD_PATH, path),
584	                    UseKind::Normal => {
585	                        if current_file_dir.is_empty() {
586	                            path.to_string()
587	                        } else {
588	                            format!("{}/{}", current_file_dir, path)
589	                        }
590	                    }
591	                };
592	
593	                if !Path::new(&full_path).exists() {
594	                    error(*span, "File does not exist!", "pre-transpiling");
595	                    return;
596	                }
597	
598	                if !programs_to_transpile.contains_key(&full_path) {
599	                    programs_to_transpile.insert(full_path.clone(), true);
600	                    // Process this file immediately so its functions are available to subsequent
601	                    // declarations in the current file
602	                    let source = std::fs::read_to_string(&full_path)
603	                        .unwrap_or_else(|_| panic!("Failed to read {}", full_path));
604	                    let imported_ast = {
605	                        let mut scanner = crate::scanner::Scanner::new(source.clone());
606	                        let tokens = scanner.scan_tokens();
607	                        let mut parser = crate::parser::Parser::new(tokens);
608	                        parser.parse()
609	                    };
610	                    let imported_dir = std::path::Path::new(&full_path)
611	                        .parent()
612	                        .map(|p| p.to_string_lossy().to_string())
613	                        .unwrap_or_default();
614	                    imported_ast.pre_transpile(cte, ctx, programs_to_transpile, &imported_dir);
615	                }
616	            }
617	
618	            Expr::StmtBlock(exprs, _) | Expr::StmtBlockWithScope(exprs, _) => {
619	                for expr in exprs {
620	                    expr.pre_transpile(cte, ctx, programs_to_transpile, current_file_dir);
621	                }
622	            }
623	
624	            Expr::Discard(expr) => expr.pre_transpile(cte, ctx, programs_to_transpile, current_file_dir),
625	
626	            Expr::Class(ty, members, span) => {
627	                cte.register_class(ty.clone());
628	
629	                for member in members {
630	                    cte.declare_member(member.0.clone(), member.1.clone(), ty.clone());
631	                }
632	
633	                let c_type_name = cte.c_type_name(ty, *span);
634	                ctx.include.push_str("struct ");
635	                ctx.include.push_str(&c_type_name);
636	                ctx.include.push_str(";\n");
637	
638	                ctx.types.push_str("\ntypedef struct ");
639	                ctx.types.push_str(&c_type_name);
640	                ctx.types.push(' ');
641	                ctx.types.push_str(&c_type_name);
642	                ctx.types.push_str(";\n");
643	            }
644	
645	            Expr::Declare(name, var_type, expr, is_mutable, _span) => {
646	                if let Some(var_type) = var_type {
647	                    cte.declare_var(name.clone(), *is_mutable, var_type.clone());
648	                } else if let Some(expr_box) = expr {
649	                    let t = expr_box.get_type(cte);
650	                    cte.declare_var(name.clone(), *is_mutable, t);
651	                }
652	                if let Some(expr_box) = expr {
653	                    expr_box.pre_transpile(cte, ctx, programs_to_transpile, current_file_dir);
654	                }
655	            }
656	
657	            _ => {}
658	        }
659	    }
660	
661	    fn get_type(&self, cte: &CompileTimeEnv) -> Type {
662	        match self {
663	            Expr::Int(_) => "i32".into(),
664	            Expr::Float(_) => "f64".into(),
665	            Expr::Str(_) => "strlit".into(),
666	            Expr::Bool(_)
667	            | Expr::EqualEqual(..)
668	            | Expr::BangEqual(..)
669	            | Expr::Less(..)
670	            | Expr::LessEqual(..)
671	            | Expr::Greater(..)
672	            | Expr::GreaterEqual(..) => "bool".into(),
673	            Expr::Char(_) => "char".into(),
674	            Expr::Add(l, _, _)
675	            | Expr::Sub(l, ..)
676	            | Expr::Mult(l, ..)
677	            | Expr::Power(l, ..)
678	            | Expr::Div(l, ..) => l.get_type(cte),
679	            Expr::Return(_, _span) => nil_type(),
680	            Expr::CallFunc(name, _, _, span) => {
681	                let function = cte
682	                    .get_var(name)
683	                    .unwrap_or_else(|| {
684	                        error(
685	                            *span,
686	                            &format!("Function not defined: {}", name),
687	                            "type checker",
688	                        );
689	                        (false, nil_type())
690	                    })
691	                    .1;
692	                function.generics()[0].clone()
693	            }
694	            Expr::StmtBlock(exprs, _span) => exprs.last().unwrap().get_type(cte),
695	            Expr::StmtBlockWithScope(exprs, _span) => exprs.last().unwrap().get_type(cte),
696	            Expr::Variable(name, span) => {
697	                cte.get_var(name)
698	                    .unwrap_or_else(|| {
699	                        error(
700	                            *span,
701	                            &format!("Variable not defined: {}", name),
702	                            "type checker",
703	                        );
704	                        (false, nil_type())
705	                    })
706	                    .1
707	            }
708	            Expr::Discard(..) => nil_type(),
709	            Expr::Print(expr, _) => expr.get_type(cte),
710	            Expr::If(_, block, ..) => block.get_type(cte),
711	            Expr::Member(variable, member_name, span) => {
712	                let var = cte.get_var(variable);
713	                if var.is_none() {
714	                    error(
715	                        *span,
716	                        &format!("Variable '{}' not defined", variable),
717	                        "type checker",
718	                    );
719	                }
720	                let variable = var.unwrap();
721	                let var_type = variable.1;
722	
723	                let member = cte.get_member_type(&var_type, member_name);
724	
725	                let member_type = if member.is_none() {
726	                    error(
727	                        *span,
728	                        &format!(
729	                            "Member '{}' not defined for type '{}'",
730	                            member_name, var_type
731	                        ),
732	                        "type checker",
733	                    );
734	                    nil_type()
735	                } else {
736	                    member.unwrap()
737	                };
738	
739	                member_type
740	            }
741	            _ => panic!("unexpected expression (for type check) '{:?}'", self),
742	        }
743	    }
744	
745	    fn returned_type(&self, cte: &CompileTimeEnv, span: Span) -> Option<Type> {
746	        match self {
747	            Expr::Return(expr, _span) => Some(expr.get_type(cte)),
748	            Expr::Discard(expr) => expr.returned_type(cte, span),
749	            Expr::StmtBlock(exprs, span) => {
750	                let mut return_type = None;
751	                for expr in exprs {
752	                    let ret_type = expr.returned_type(cte, *span);
753	                    if let Some(returned_type) = ret_type {
754	                        if let Some(expected_type) = return_type.clone() {
755	                            if expected_type != returned_type {
756	                                error(
757	                                    {
758	                                        let expr_span = expr.get_span();
759	                                        if expr_span == Span::empty() {
760	                                            *span
761	                                        } else {
762	                                            expr_span
763	                                        }
764	                                    },
765	                                    "Returned type was different to previous returned type",
766	                                    "returned type checker",
767	                                );
768	                            }
769	                        } else {
770	                            return_type = Some(returned_type);
771	                        }
772	                    }
773	                }
774	                return_type
775	            }
776	            Expr::StmtBlockWithScope(exprs, span) => {
777	                Expr::StmtBlock(exprs.clone(), *span).returned_type(cte, *span)
778	            }
779	            _ => None,
780	        }
781	    }
782	
783	    fn get_span(&self) -> Span {
784	        match self {
785	            Expr::Add(_, _, span)
786	            | Expr::Sub(_, _, span)
787	            | Expr::Mult(_, _, span)
788	            | Expr::Div(_, _, span)
789	            | Expr::Power(_, _, span)
790	            | Expr::Mod(_, _, span)
791	            | Expr::BangEqual(_, _, span)
792	            | Expr::EqualEqual(_, _, span)
793	            | Expr::GreaterEqual(_, _, span)
794	            | Expr::LessEqual(_, _, span)
795	            | Expr::Less(_, _, span)
796	            | Expr::Greater(_, _, span)
797	            | Expr::Return(_, span) => *span,
798	            _ => Span::empty(),
799	        }
800	    }
801	}
