126	
127	    fn delete(&mut self) -> Expr {
128	        if self.match_any(&[TokenType::Ident]) {
129	            Expr::Delete(self.previous().lexeme)
130	        } else {
131	            error(
132	                self.get_span(),
133	                "Expected variable name after 'del'.",
134	                "parsing",
135	            );
136	            Expr::Nothing()
137	        }
138	    }
