210	    // ---------- DECLARATION ----------
211	    fn declaration(&mut self) -> Expr {
212	        let is_mutable = self.match_any(&[TokenType::At]);
213	
214	        self.consume(TokenType::Ident, "Expected variable name.");
215	        let name = self.previous().lexeme.clone();
216	
217	        let var_type = if self.match_any(&[TokenType::Colon]) {
218	            Some(self.get_type())
219	        } else {
220	            None
221	        };
222	        let expr = if self.match_any(&[TokenType::Equal]) {
223	            Some(Box::new(self.expression()))
224	        } else {
225	            None
226	        };
227	
228	        if var_type.is_none() && expr.is_none() {
229	            let span = self.get_span();
230	            error(
231	                span,
232	                "Expected type or expression or both, got neither",
233	                "parsing",
234	            );
235	        }
236	        Expr::Declare(name, var_type, expr, is_mutable, self.get_span())
237	    }
