239	    // ------- IF / ELSE IF / ELSE ----
240	
241	    fn if_statement(&mut self, is_expr: bool) -> Expr {
242	        let if_cond = self.expression();
243	        // self.current += 1;
244	        let if_block = if self.match_any(&[TokenType::LeftBrace]) {
245	            self.statement_block()
246	        } else {
247	            error(
248	                self.get_span(),
249	                ("Expected '{' after 'if' condition, found '".to_string()
250	                    + self.previous().lexeme.as_str()
251	                    + "'")
252	                    .as_str(),
253	                "parsing",
254	            );
255	            Expr::Nothing()
256	        };
257	
258	        let mut else_block = None;
259	
260	        if self.match_any(&[TokenType::TildeQuestionMark]) {
261	            else_block = Some(Box::new(self.if_statement(is_expr)));
262	        } else if self.match_any(&[TokenType::Tilde]) {
263	            self.consume(TokenType::LeftBrace, "Expected '{' after 'TILDE'.");
264	            else_block = Some(Box::new(self.statement_block()));
265	        }
266	
267	        Expr::If(Box::new(if_cond), Box::new(if_block), else_block, is_expr)
268	    }
269	    // ---------- PRINT ---------------
270	    fn print(&mut self) -> Expr {
271	        if self.peek().token_type == TokenType::Dollar {
272	            self.advance();
273	            Expr::StmtBlock(
274	                vec![
275	                    Box::new(self.print()),
276	                    Box::new(Expr::Print(
277	                        Box::new(Expr::Str("\n".to_string())),
278	                        self.get_span(),
279	                    )),
280	                ],
281	                self.get_span(),
282	            )
283	        } else if self.peek().token_type == TokenType::Semicolon {
284	            Expr::Nothing()
285	        } else {
286	            Expr::Print(Box::new(self.expression()), self.get_span())
287	        }
288	    }
