      // Use -> when variable is a pointer (struct params) or . otherwise
      // Variables declared as class types are pointers when passed as function params,
      // but local variables are not. Check: if it's a class type in scope,
      // and it could be a param, use the appropriate accessor.
      // We check if the type is a class — if so, we need to determine
      // if the variable is stored as a pointer. Function params are pointers;
      // local variables are values.
      // For simplicity: if variable is declared as a class type and was
      // declared as a function parameter, it's a pointer.
      // Check the scopes to see if this is a param (immutable class = likely param)
      let is_param_pointer = {
          // Find which scope this variable is in
          let found_scope = cte.resolve_scope(variable);
          if found_scope == 1 && cte.is_class(&variable.1) {
              // Scope 1 = function parameter scope for body params
              true
          } else {
              false
          }
      };

      if is_param_pointer {
          ctx.body.push_str("->");
      } else {
          ctx.body.push('.');
