1	use crate::expr::UseKind;
2	use crate::span::Span;
3	use crate::token_type::TokenType::Pound;
4	use crate::type_env::{nil_type, Type};
5	use crate::{error, expr::Expr, token::Token, token_type::TokenType};
6	
7	pub struct Parser<'a> {
8	    tokens: &'a [Token],
9	    current: usize,
10	}
11	
12	impl<'a> Parser<'a> {
13	    pub fn new(tokens: &'a [Token]) -> Self {
14	        Self { tokens, current: 0 }
15	    }
16	
17	    // ---------- ENTRY ----------
18	    pub fn parse(&mut self) -> Expr {
19	        let mut statements = Vec::new();
20	
21	        while !self.is_at_end() {
22	            statements.push(Box::new(self.statement()));
23	            if !self.match_any(&[TokenType::Semicolon]) && !self.is_at_end() {
24	                let t = self.peek();
25	                error(
26	                    self.get_span(),
27	                    format!("Expected ';' after statement. Found '{}'", t.token_type).as_str(),
28	                    "parsing",
29	                );
30	                self.advance();
31	            }
32	        }
33	
34	        Expr::StmtBlock(statements, self.get_span())
35	    }
36	
37	    // ---------- STATEMENTS ----------
38	    fn statement(&mut self) -> Expr {
39	        if self.match_any(&[TokenType::Dollar]) {
40	            return self.print();
41	        }
42	
43	        if self.match_any(&[TokenType::Ret]) {
44	            return self.return_stmt();
45	        }
46	
47	        if self.match_any(&[Pound]) {
48	            return self.while_loop();
49	        }
50	
51	        if self.match_any(&[TokenType::Fn]) {
52	            return self.define_function();
53	        }
54	
55	        if self.match_any(&[TokenType::Hash]) {
56	            return self.declaration();
57	        }
58	
59	        if self.match_any(&[TokenType::Del]) {
60	            return self.delete();
61	        }
62	
63	        if self.match_any(&[TokenType::QuestionMark]) {
64	            return self.if_statement(false);
65	        }
66	
67	        if self.match_any(&[TokenType::Use]) {
68	            return self.use_file();
69	        }
70	
71	        if self.match_any(&[TokenType::For]) {
72	            return self.for_loop();
73	        }
74	
75	        if self.match_any(&[TokenType::Cls]) {
76	            return self.class();
77	        }
78	
79	        Expr::Stmt(Box::new(self.expression()))
80	    }
81	
82	    // ---------- USE ------------
83	
84	    fn use_file(&mut self) -> Expr {
85	        let kind = if self.match_any(&[TokenType::Std]) {
86	            UseKind::Std
87	        } else {
88	            UseKind::Normal
89	        };
90	        self.consume(TokenType::String, "Expected file name after 'use' keyword");
91	        Expr::Use {
92	            kind,
93	            path: self.previous().literal,
94	            span: self.get_span(),
95	        }
96	    }
97	
98	    // ---------- BLOCK ----------
99	    fn statement_block(&mut self) -> Expr {
100	        let mut statements = Vec::new();
101	
102	        while !self.check(TokenType::RightBrace) && !self.is_at_end() {
103	            let statement = self.statement();
104	
105	            if !self.check(TokenType::Semicolon) && !self.check(TokenType::RightBrace) {
106	                let t = self.peek();
107	                error(
108	                    self.get_span(),
109	                    format!("Expected ';' after statement. Found '{}'", t.token_type).as_str(),
110	                    "parsing",
111	                );
112	                self.advance();
113	            }
114	            if self.match_any(&[TokenType::Semicolon]) {
115	                statements.push(Box::new(Expr::Discard(Box::new(statement))));
116	            } else {
117	                statements.push(Box::new(statement));
118	            }
119	        }
120	
121	        self.consume(TokenType::RightBrace, "Expected '}' after block.");
122	        Expr::StmtBlockWithScope(statements, self.get_span())
123	    }
124	
125	    // ---------- DELETE VAR -----------
126	
127	    fn delete(&mut self) -> Expr {
128	        if self.match_any(&[TokenType::Ident]) {
129	            Expr::Delete(self.previous().lexeme)
130	        } else {
131	            error(
132	                self.get_span(),
133	                "Expected variable name after 'del'.",
134	                "parsing",
135	            );
136	            Expr::Nothing()
137	        }
138	    }
139	
140	    // ---------- NEW CLASS -----------
141	
142	    fn class(&mut self) -> Expr {
143	        self.consume(TokenType::Ident, "Expected class name after 'cls'.");
144	        let name = self.previous().lexeme;
145	        self.consume(TokenType::LeftBrace, "Expected '{' after class name");
146	
147	        let mut members = Vec::new();
148	
149	        while !self.match_any(&[TokenType::RightBrace]) {
150	            self.consume(
151	                TokenType::Ident,
152	                "Expected an identifier at start of line (in class declaration)",
153	            );
154	            let name = self.previous().lexeme;
155	            self.consume(
156	                TokenType::Colon,
157	                "Expected colon after identifier in class declaration",
158	            );
159	
160	            members.push((name, self.get_type()));
161	        }
162	
163	        let class_type = Type::simple(&name);
164	
165	        Expr::Class(class_type, members, self.get_span())
166	    }
167	    // ---------- MEMBER VARIABLE -----------
168	
169	    fn member(&mut self, variable: String) -> Expr {
170	        let member = self.ident();
171	
172	        Expr::Member(variable, member, self.get_span())
173	    }
174	
175	    // ---------- WHILE LOOP -----------
176	
177	    fn while_loop(&mut self) -> Expr {
178	        let cond = self.expression();
179	        // self.current += 1;
180	        let block = if self.match_any(&[TokenType::LeftBrace]) {
181	            self.statement_block()
182	        } else {
183	            error(
184	                self.get_span(),
185	                ("Expected '{' after 'while' condition, found '".to_string()
186	                    + self.previous().lexeme.as_str()
187	                    + "'")
188	                    .as_str(),
189	                "parsing",
190	            );
191	            Expr::Nothing()
192	        };
193	
194	        Expr::While(Box::new(cond), Box::new(block))
195	    }
196	
197	    // ----------- FOR LOOP -----------
198	
199	    fn for_loop(&mut self) -> Expr {
200	        self.consume(TokenType::Ident, "Expected identifier after 'For' token");
201	        let loopee = self.previous().lexeme;
202	        self.consume(TokenType::Colon, "Expected ':' after loopee");
203	        let looper = self.expression();
204	        self.consume(TokenType::LeftBrace, "Expected '{' after looper");
205	        let block = self.statement_block();
206	
207	        Expr::For(loopee, Box::new(looper), Box::new(block), self.get_span())
208	    }
209	
210	    // ---------- DECLARATION ----------
211	    fn declaration(&mut self) -> Expr {
212	        let is_mutable = self.match_any(&[TokenType::At]);
213	
214	        self.consume(TokenType::Ident, "Expected variable name.");
215	        let name = self.previous().lexeme.clone();
216	
217	        let var_type = if self.match_any(&[TokenType::Colon]) {
218	            Some(self.get_type())
219	        } else {
220	            None
221	        };
222	        let expr = if self.match_any(&[TokenType::Equal]) {
223	            Some(Box::new(self.expression()))
224	        } else {
225	            None
226	        };
227	
228	        if var_type.is_none() && expr.is_none() {
229	            let span = self.get_span();
230	            error(
231	                span,
232	                "Expected type or expression or both, got neither",
233	                "parsing",
234	            );
235	        }
236	        Expr::Declare(name, var_type, expr, is_mutable, self.get_span())
237	    }
238	
239	    // ------- IF / ELSE IF / ELSE ----
240	
241	    fn if_statement(&mut self, is_expr: bool) -> Expr {
242	        let if_cond = self.expression();
243	        // self.current += 1;
244	        let if_block = if self.match_any(&[TokenType::LeftBrace]) {
245	            self.statement_block()
246	        } else {
247	            error(
248	                self.get_span(),
249	                ("Expected '{' after 'if' condition, found '".to_string()
250	                    + self.previous().lexeme.as_str()
251	                    + "'")
252	                    .as_str(),
253	                "parsing",
254	            );
255	            Expr::Nothing()
256	        };
257	
258	        let mut else_block = None;
259	
260	        if self.match_any(&[TokenType::TildeQuestionMark]) {
261	            else_block = Some(Box::new(self.if_statement(is_expr)));
262	        } else if self.match_any(&[TokenType::Tilde]) {
263	            self.consume(TokenType::LeftBrace, "Expected '{' after 'TILDE'.");
264	            else_block = Some(Box::new(self.statement_block()));
265	        }
266	
267	        Expr::If(Box::new(if_cond), Box::new(if_block), else_block, is_expr)
268	    }
269	    // ---------- PRINT ---------------
270	    fn print(&mut self) -> Expr {
271	        if self.peek().token_type == TokenType::Dollar {
272	            self.advance();
273	            Expr::StmtBlock(
274	                vec![
275	                    Box::new(self.print()),
276	                    Box::new(Expr::Print(
277	                        Box::new(Expr::Str("\n".to_string())),
278	                        self.get_span(),
279	                    )),
280	                ],
281	                self.get_span(),
282	            )
283	        } else if self.peek().token_type == TokenType::Semicolon {
284	            Expr::Nothing()
285	        } else {
286	            Expr::Print(Box::new(self.expression()), self.get_span())
287	        }
288	    }
289	
290	    // ---------- FUNCTIONS ------------
291	
292	    fn define_function(&mut self) -> Expr {
293	        let mut generic_params = vec![];
294	
295	        if self.match_any(&[TokenType::LessLess]) {
296	            loop {
297	                self.consume(TokenType::Ident, "Expected generic name");
298	                generic_params.push(self.previous().lexeme);
299	
300	                if !self.match_any(&[TokenType::Comma]) {
301	                    break;
302	                }
303	            }
304	            self.consume(TokenType::GreaterGreater, "Expected '>'");
305	        }
306	
307	        let name = self.advance().lexeme;
308	
309	        let start_span = self.get_span();
310	
311	        let parameters: Vec<(String, Type)> = if self.match_any(&[TokenType::LeftParen]) {
312	            let mut parameters = vec![];
313	            while !self.is_at_end() && !self.check(TokenType::RightParen) {
314	                let name = self.advance().lexeme;
315	                self.consume(TokenType::Colon, "Expected ':' after parameter name.");
316	                let var_type = self.get_type();
317	                parameters.push((name, var_type));
318	                if !self.match_any(&[TokenType::Comma]) {
319	                    break;
320	                }
321	            }
322	
323	            self.consume(
324	                TokenType::RightParen,
325	                "Expected ')' after function parameters.",
326	            );
327	            parameters
328	        } else {
329	            vec![]
330	        };
331	
332	        let return_type = if !self.check(TokenType::LeftBrace) {
333	            Some(self.get_type())
334	        } else {
335	            None
336	        };
337	
338	        self.consume(
339	            TokenType::LeftBrace,
340	            "Expected '{' after function declaration.",
341	        );
342	
343	        let body = Box::new(self.statement_block());
344	
345	        Expr::DeclareFunction(
346	            name,
347	            body,
348	            return_type,
349	            parameters,
350	            generic_params,
351	            start_span,
352	        )
353	    }
354	
355	    fn define_lambda(&mut self) -> Expr {
356	        let mut generic_params = vec![];
357	
358	        if self.match_any(&[TokenType::LessLess]) {
359	            loop {
360	                self.consume(TokenType::Ident, "Expected generic name");
361	                generic_params.push(self.previous().lexeme);
362	
363	                if !self.match_any(&[TokenType::Comma]) {
364	                    break;
365	                }
366	            }
367	            self.consume(TokenType::GreaterGreater, "Expected '>'");
368	        }
369	
370	        let parameters: Vec<(String, Type)> = if self.match_any(&[TokenType::LeftParen]) {
371	            let mut parameters = vec![];
372	            while !self.is_at_end() && !self.check(TokenType::RightParen) {
373	                let name = self.advance().lexeme;
374	                self.consume(TokenType::Colon, "Expected ':' after parameter name.");
375	                let var_type = self.get_type();
376	                parameters.push((name, var_type));
377	                if !self.match_any(&[TokenType::Comma]) {
378	                    break;
379	                }
380	            }
381	
382	            self.consume(
383	                TokenType::RightParen,
384	                "Expected ')' after function parameters.",
385	            );
386	            parameters
387	        } else {
388	            vec![]
389	        };
390	
391	        let return_type = if !self.check(TokenType::LeftBrace) {
392	            self.get_type()
393	        } else {
394	            nil_type()
395	        };
396	
397	        self.consume(
398	            TokenType::LeftBrace,
399	            "Expected '{' after function declaration.",
400	        );
401	
402	        let body = Box::new(self.statement_block());
403	
404	        Expr::Function(body, return_type, parameters, generic_params)
405	    }
406	
407	    fn return_stmt(&mut self) -> Expr {
408	        let value = self.expression();
409	        Expr::Return(Box::new(value), self.get_span())
410	    }
411	
412	    fn call_function(&mut self, name: String) -> Expr {
413	        let mut generics = vec![];
414	
415	        if self.match_any(&[TokenType::LessLess]) {
416	            loop {
417	                generics.push(self.get_type());
418	
419	                if !self.match_any(&[TokenType::Comma]) {
420	                    break;
421	                }
422	            }
423	            self.consume(TokenType::GreaterGreater, "Expected '>' after generics");
424	        }
425	
426	        self.consume(TokenType::LeftParen, "Expected '(' after function name.");
427	
428	        let mut arguments = vec![];
429	
430	        if !self.check(TokenType::RightParen) {
431	            loop {
432	                arguments.push(Box::new(self.expression()));
433	                if !self.match_any(&[TokenType::Comma]) {
434	                    break;
435	                }
436	            }
437	        }
438	
439	        self.consume(TokenType::RightParen, "Missing ')' after function call.");
440	
441	        Expr::CallFunc(name, generics, arguments, self.get_span())
442	    }
443	
444	    // ---------- EXPRESSIONS ----------
445	    fn expression(&mut self) -> Expr {
446	        self.bools()
447	    }
448	
449	    fn bools(&mut self) -> Expr {
450	        let mut expr = self.compare();
451	
452	        while self.match_any(&[TokenType::And, TokenType::Or]) {
453	            let op = self.previous().token_type;
454	            let right = self.compare();
455	            expr = match op {
456	                TokenType::And => Expr::And(Box::new(expr), Box::new(right), self.get_span()),
457	                TokenType::Or => Expr::Or(Box::new(expr), Box::new(right), self.get_span()),
458	                _ => unreachable!(),
459	            };
460	        }
461	
462	        expr
463	    }
464	
465	    fn compare(&mut self) -> Expr {
466	        let mut expr = self.term();
467	
468	        while self.match_any(&[
469	            TokenType::EqualEqual,
470	            TokenType::BangEqual,
471	            TokenType::Greater,
472	            TokenType::GreaterEqual,
473	            TokenType::Less,
474	            TokenType::LessEqual,
475	        ]) {
476	            let op = self.previous().token_type;
477	            let right = self.term();
478	            expr = match op {
479	                TokenType::EqualEqual => {
480	                    Expr::EqualEqual(Box::new(expr), Box::new(right), self.get_span())
481	                }
482	                TokenType::BangEqual => {
483	                    Expr::BangEqual(Box::new(expr), Box::new(right), self.get_span())
484	                }
485	                TokenType::Greater => {
486	                    Expr::Greater(Box::new(expr), Box::new(right), self.get_span())
487	                }
488	                TokenType::GreaterEqual => {
489	                    Expr::GreaterEqual(Box::new(expr), Box::new(right), self.get_span())
490	                }
491	                TokenType::Less => Expr::Less(Box::new(expr), Box::new(right), self.get_span()),
492	                TokenType::LessEqual => {
493	                    Expr::LessEqual(Box::new(expr), Box::new(right), self.get_span())
494	                }
495	                _ => unreachable!(),
496	            };
497	        }
498	
499	        expr
500	    }
501	
502	    fn term(&mut self) -> Expr {
503	        let mut expr = self.factor();
504	
505	        while self.match_any(&[TokenType::Plus, TokenType::Minus]) {
506	            let op = self.previous().token_type;
507	            let right = self.factor();
508	            expr = match op {
509	                TokenType::Plus => Expr::Add(Box::new(expr), Box::new(right), self.get_span()),
510	                TokenType::Minus => Expr::Sub(Box::new(expr), Box::new(right), self.get_span()),
511	                _ => unreachable!(),
512	            };
513	        }
514	
515	        expr
516	    }
517	
518	    fn factor(&mut self) -> Expr {
519	        let mut expr = self.unary();
520	
521	        while self.match_any(&[TokenType::Star, TokenType::Slash, TokenType::Mod]) {
522	            let op = self.previous().token_type;
523	            let right = self.unary();
524	            expr = match op {
525	                TokenType::Star => Expr::Mult(Box::new(expr), Box::new(right), self.get_span()),
526	                TokenType::Slash => Expr::Div(Box::new(expr), Box::new(right), self.get_span()),
527	                TokenType::Mod => Expr::Mod(Box::new(expr), Box::new(right), self.get_span()),
528	                _ => unreachable!(),
529	            };
530	        }
531	
532	        expr
533	    }
534	
535	    fn unary(&mut self) -> Expr {
536	        if self.match_any(&[TokenType::Minus]) {
537	            return Expr::Sub(
538	                Box::new(Expr::Nothing()),
539	                Box::new(self.unary()),
540	                self.get_span(),
541	            );
542	        }
543	
544	        if self.match_any(&[TokenType::Plus]) {
545	            return Expr::Add(
546	                Box::new(Expr::Nothing()),
547	                Box::new(self.unary()),
548	                self.get_span(),
549	            );
550	        }
551	
552	        if self.match_any(&[TokenType::Bang]) {
553	            return Expr::Not(Box::new(self.unary()));
554	        }
555	
556	        if self.match_any(&[TokenType::And]) {
557	            // Make a reference to the variable itself
558	            return if self.check(TokenType::Ident) {
559	                self.advance(); // consume the identifier
560	                let var_name = self.previous().lexeme.clone();
561	                Expr::CallFunc(
562	                    "ref::new".into(),
563	                    vec![],
564	                    vec![Box::new(Expr::Str(var_name))],
565	                    self.get_span(),
566	                )
567	            } else {
568	                error(self.get_span(), "Expected identifier after '&'.", "parsing");
569	                Expr::Nothing()
570	            };
571	        }
572	
573	        if self.match_any(&[TokenType::Star]) {
574	            let expr = self.unary();
575	            return Expr::CallFunc(
576	                "ref::deref".into(),
577	                vec![],
578	                vec![Box::new(expr)],
579	                self.get_span(),
580	            );
581	        }
582	
583	        self.power()
584	    }
585	
586	    fn power(&mut self) -> Expr {
587	        let mut expr = self.nth();
588	
589	        while self.match_any(&[TokenType::StarStar]) {
590	            expr = Expr::Power(Box::new(expr), Box::new(self.nth()), self.get_span());
591	        }
592	
593	        expr
594	    }
595	    fn nth(&mut self) -> Expr {
596	        let val = self.primary();
597	        if self.match_any(&[TokenType::LeftBrack]) {
598	            let expr = self.expression();
599	            self.consume(TokenType::RightBrack, "Expected ']' after indexing.");
600	            Expr::Nth(Box::new(val), Box::new(expr), self.get_span())
601	        } else {
602	            val
603	        }
604	    }
605	
606	    fn vector_lit(&mut self) -> Expr {
607	        if self.match_any(&[TokenType::LeftBrace]) {
608	            let mut exprs = vec![];
609	
610	            let mut last_expr = false;
611	            while !self.match_any(&[TokenType::RightBrace]) && !last_expr {
612	                let expr = self.expression();
613	                exprs.push(expr);
614	                if !self.match_any(&[TokenType::Comma]) {
615	                    last_expr = true;
616	                }
617	            }
618	
619	            Expr::Vector(exprs)
620	        } else {
621	            self.consume(TokenType::LeftBrace, "Expected '{' after '\\''.");
622	            Expr::Nothing()
623	        }
624	    }
625	
626	    fn array_lit(&mut self) -> Expr {
627	        let mut exprs = vec![];
628	
629	        let mut last_expr = false;
630	        while !self.match_any(&[TokenType::RightBrack]) && !last_expr {
631	            let expr = self.expression();
632	            exprs.push(expr);
633	            if !self.match_any(&[TokenType::Comma]) {
634	                last_expr = true;
635	            }
636	        }
637	
638	        Expr::Array(exprs)
639	    }
640	
641	    // ---------- PRIMARY ----------
642	    fn primary(&mut self) -> Expr {
643	        if self.match_any(&[TokenType::LeftBrace]) {
644	            return self.statement_block();
645	        }
646	
647	        if self.check(TokenType::Ident) {
648	            let item = self.item();
649	
650	            if self.check(TokenType::LeftParen) {
651	                return self.call_function(item);
652	            }
653	            if self.match_any(&[TokenType::Dot]) {
654	                let member_expr = self.member(item);
655	                // NEW: Check for assignment after member access
656	                if self.match_any(&[TokenType::Equal]) {
657	                    let span = self.get_span();
658	                    return Expr::Assign(Box::new(member_expr), Box::new(self.expression()), span);
659	                }
660	                return member_expr;
661	            }
662	            if self.match_any(&[TokenType::Equal]) {
663	                let span = self.get_span();
664	                return Expr::Assign(
665	                    Box::new(Expr::Variable(item, self.get_span())),
666	                    Box::new(self.expression()),
667	                    span,
668	                );
669	            }
670	            return Expr::Variable(item, self.get_span());
671	        }
672	
673	        if self.match_any(&[TokenType::Float]) {
674	            return Expr::Float(self.previous().literal.parse().unwrap_or(0.0));
675	        }
676	
677	        if self.match_any(&[TokenType::Int]) {
678	            return Expr::Int(self.previous().literal.parse().unwrap_or(0));
679	        }
680	
681	        if self.match_any(&[TokenType::True]) {
682	            return Expr::Bool(true);
683	        }
684	
685	        if self.match_any(&[TokenType::False]) {
686	            return Expr::Bool(false);
687	        }
688	
689	        if self.match_any(&[TokenType::String]) {
690	            return Expr::Str(self.previous().literal.clone());
691	        }
692	
693	        if self.match_any(&[TokenType::Char]) {
694	            return Expr::Char(self.previous().literal.clone());
695	        }
696	
697	        if self.match_any(&[TokenType::LeftParen]) {
698	            let expr = self.expression();
699	            self.consume(TokenType::RightParen, "Expected ')'.");
700	            return expr;
701	        }
702	
703	        if self.match_any(&[TokenType::QuestionMark]) {
704	            return self.if_statement(true);
705	        }
706	
707	        if self.match_any(&[TokenType::This]) {
708	            return Expr::This(self.get_span());
709	        }
710	
711	        if self.match_any(&[TokenType::Lam]) {
712	            return self.define_lambda();
713	        }
714	
715	        if self.match_any(&[TokenType::BackSlash]) {
716	            return self.vector_lit();
717	        }
718	
719	        if self.match_any(&[TokenType::LeftBrack]) {
720	            return self.array_lit();
721	        }
722	
723	        Expr::Nothing()
724	    }
725	
726	    fn get_type(&mut self) -> Type {
727	        if self.match_any(&[TokenType::Ident]) {
728	            let name = self.previous().lexeme.clone();
729	
730	            if self.match_any(&[TokenType::LessLess]) {
731	                let mut gens = vec![];
732	
733	                loop {
734	                    gens.push(self.get_type());
735	                    if !self.match_any(&[TokenType::Comma]) {
736	                        break;
737	                    }
738	                }
739	
740	                self.consume(TokenType::GreaterGreater, "Expected '>' after generics");
741	                return Type::with_generics(&name, gens);
742	            }
743	
744	            return Type::simple(&name);
745	        } else if self.match_any(&[TokenType::LeftBrack]) {
746	            let mut gens = vec![];
747	
748	            loop {
749	                gens.push(self.get_type());
750	                if !self.match_any(&[TokenType::Comma]) {
751	                    break;
752	                }
753	            }
754	
755	            self.consume(TokenType::RightBrack, "Expected '>' after generics");
756	            return Type::with_generics("arr", gens);
757	        }
758	
759	        nil_type()
760	    }
761	
762	    // ---------- UTIL ----------
763	    fn get_span(&self) -> Span {
764	        let token = self.previous();
765	        Span {
766	            line: token.line,
767	            column: token.column,
768	        }
769	    }
770	
771	    fn item(&mut self) -> String {
772	        self.consume(TokenType::Ident, "Expected item.");
773	        let item = self.previous().lexeme.clone();
774	        item
775	    }
776	
777	    fn ident(&mut self) -> String {
778	        self.consume(TokenType::Ident, "Expected identifier.");
779	        let ident = self.previous().lexeme.clone();
780	        ident
781	    }
782	
783	    fn match_any(&mut self, types: &[TokenType]) -> bool {
784	        for t in types {
785	            if self.check(*t) {
786	                self.advance();
787	                return true;
788	            }
789	        }
790	        false
791	    }
792	    fn check(&self, token_type: TokenType) -> bool {
793	        !self.is_at_end() && self.peek().token_type == token_type
794	    }
795	
796	    fn peek_next(&self, token_type: TokenType) -> bool {
797	        self.tokens
798	            .get(self.current + 1)
799	            .map(|t| t.token_type == token_type)
800	            .unwrap_or(false)
801	    }
802	
803	    fn peek_next_next(&self, token_type: TokenType) -> bool {
804	        self.tokens
805	            .get(self.current + 2)
806	            .map(|t| t.token_type == token_type)
807	            .unwrap_or(false)
808	    }
809	
810	    fn consume(&mut self, token_type: TokenType, message: &str) -> Token {
811	        if self.check(token_type) {
812	            self.advance()
813	        } else {
814	            let t = self.peek();
815	            error(
816	                self.get_span(),
817	                format!("{} Found: {}", message, t.token_type).as_str(),
818	                "parsing",
819	            );
820	            self.advance();
821	            Token::nil()
822	        }
823	    }
824	
825	    fn advance(&mut self) -> Token {
826	        if !self.is_at_end() {
827	            self.current += 1;
828	        }
829	        self.previous()
830	    }
831	
832	    fn is_at_end(&self) -> bool {
833	        self.peek().token_type == TokenType::EOF
834	    }
835	
836	    fn peek(&self) -> Token {
837	        self.tokens
838	            .get(self.current)
839	            .cloned()
840	            .unwrap_or_else(Token::nil)
841	    }
842	
843	    fn previous(&self) -> Token {
844	        self.tokens
845	            .get(self.current.saturating_sub(1))
846	            .cloned()
847	            .unwrap_or_else(Token::nil)
848	    }
849	}
