851	// Grammar:
852	/*
853	statement_block -> "{" ( statement )* "}"
854	statement       -> ( print | declaration | expression | return | function ) ";"
855	
856	print           -> "$" ( "$" )? expression
857	declaration     -> "#" ( "@" )? IDENTIFIER ( ":" type )? ( "=" expression )? // need one or both
858	return          -> "ret" expression
859	while           -> "£" expression statement_block
860	
861	if_statement    -> "?" expression statement_block ( "~?" expression statement_block )* ( "~" statement_block )?
862	function_call   -> IDENTIFIER "(" (expression)* ")"
863	function        -> "fn" ( "<<" IDENTIFIER* ">>" )? IDENTIFIER ( "(" (IDENTIFIER ":" IDENTIFIER)* ")" )? type? statement_block
864	
865	type            -> IDENTIFIER | "[" type* "]" | "<<" type* ">>"
866	
867	expression      -> bool
868	bool            -> compare ( ( "&" | "|" ) compare )*
869	compare         -> term ( ( "==" | ">=" | "<=" | ">" | "<" | "!=" ) term )*
870	term            -> factor ( ( "+" | "-" ) factor )*
871	factor          -> unary ( ( "*" | "/" | "%" ) unary )*
872	unary           -> ( "-" | "+" ) unary | power
873	power           -> nth ( ( "**" ) nth )*
874	nth             -> primary ( "[" expression "]" )?
875	primary         -> NUMBER | STRING | BOOLEAN | IDENTIFIER | "(" expression ")" | statement_block | if_statement | function_call
876	
