52	impl Expr {
53	    pub fn to_c(&self, cte: &mut CompileTimeEnv, ctx: &mut CodeGenContext) -> bool {
54	        // if true - requires a semicolon at end of statement
55	        match self {
56	            Expr::Int(n) => {
57	                ctx.body.push_str(&n.to_string());
58	                false
59	            }
60	            Expr::Float(n) => {
61	                if n.fract() == 0.0 {
62	                    ctx.body.push_str(&n.to_string());
63	                    ctx.body.push_str(".0");
64	                } else {
65	                    ctx.body.push_str(&n.to_string());
66	                }
67	                false
68	            }
69	
70	            Expr::Bool(b) => {
71	                ctx.body.push_str(if *b { "true" } else { "false" });
72	                false
73	            }
74	            Expr::Char(c) => {
75	                ctx.body.push('\'');
76	                ctx.body.push_str(&c.to_string());
77	                ctx.body.push('\'');
78	                false
79	            }
80	            Expr::Str(s) => {
81	                ctx.body.push('"');
82	                for c in s.chars() {
83	                    match c {
84	                        '\n' => ctx.body.push_str("\\n"),
85	                        '\t' => ctx.body.push_str("\\t"),
86	                        _ => ctx.body.push(c),
87	                    }
88	                }
89	                ctx.body.push('"');
90	                false
91	            }
92	
93	            Expr::Add(l, r, span) => {
94	                Expr::CallFunc(
95	                    "_add".into(),
96	                    vec![l.get_type(cte)],
97	                    vec![l.clone(), r.clone()],
98	                    *span,
99	                )
100	                .to_c(cte, ctx);
101	                false
102	            }
103	
104	            Expr::Div(l, r, span) => {
105	                Expr::CallFunc(
106	                    "_div".into(),
107	                    vec![l.get_type(cte)],
108	                    vec![l.clone(), r.clone()],
109	                    *span,
110	                )
111	                .to_c(cte, ctx);
112	                false
113	            }
114	
115	            Expr::Less(l, r, span) => {
116	                Expr::CallFunc(
117	                    "_less".into(),
118	                    vec![l.get_type(cte)],
119	                    vec![l.clone(), r.clone()],
120	                    *span,
121	                )
122	                .to_c(cte, ctx);
123	                false
124	            }
125	
126	            Expr::Power(l, r, span) => {
127	                Expr::CallFunc(
128	                    "_pow".into(),
129	                    vec![l.get_type(cte)],
130	                    vec![l.clone(), r.clone()],
131	                    *span,
132	                )
133	                .to_c(cte, ctx);
134	                false
135	            }
136	            Expr::Sub(l, r, span) => {
137	                Expr::CallFunc(
138	                    "_sub".into(),
139	                    vec![l.get_type(cte)],
140	                    vec![l.clone(), r.clone()],
141	                    *span,
142	                )
143	                .to_c(cte, ctx);
144	                false
145	            }
146	            Expr::Mult(l, r, span) => {
147	                Expr::CallFunc(
148	                    "_mult".into(),
149	                    vec![l.get_type(cte)],
150	                    vec![l.clone(), r.clone()],
151	                    *span,
152	                )
153	                .to_c(cte, ctx);
154	                false
155	            }
156	            Expr::EqualEqual(l, r, span) => {
157	                Expr::CallFunc(
158	                    "_equal".into(),
159	                    vec![l.get_type(cte)],
160	                    vec![l.clone(), r.clone()],
161	                    *span,
162	                )
163	                .to_c(cte, ctx);
164	                false
165	            }
166	            Expr::Greater(l, r, span) => {
167	                Expr::CallFunc(
168	                    "_greater".into(),
169	                    vec![l.get_type(cte)],
170	                    vec![l.clone(), r.clone()],
171	                    *span,
172	                )
173	                .to_c(cte, ctx);
174	                false
175	            }
176	            Expr::GreaterEqual(l, r, span) => {
177	                Expr::CallFunc(
178	                    "_greater_equal".into(),
179	                    vec![l.get_type(cte)],
180	                    vec![l.clone(), r.clone()],
181	                    *span,
182	                )
183	                .to_c(cte, ctx);
184	                false
185	            }
186	
187	            Expr::LessEqual(l, r, span) => {
188	                Expr::CallFunc(
189	                    "_less_equal".into(),
190	                    vec![l.get_type(cte)],
191	                    vec![l.clone(), r.clone()],
192	                    *span,
193	                )
194	                .to_c(cte, ctx);
195	                false
196	            }
197	
198	            Expr::BangEqual(l, r, span) => {
199	                Expr::CallFunc(
200	                    "_bang_equal".into(),
201	                    vec![l.get_type(cte)],
202	                    vec![l.clone(), r.clone()],
203	                    *span,
204	                )
205	                .to_c(cte, ctx);
206	                false
207	            }
208	
209	            Expr::StmtBlock(exprs, _span) => {
210	                for expr in exprs {
211	                    if expr.to_c(cte, ctx) {
212	                        ctx.body.push(';');
213	                    }
214	                    ctx.body.push('\n');
215	                }
216	                false
217	            }
218	
219	            Expr::If(if_cond, if_block, else_block, is_expr) => {
220	                if !is_expr {
221	                    ctx.body.push_str("if (");
222	                    if_cond.to_c(cte, ctx);
223	                    ctx.body.push_str(")");
224	                    if_block.to_c(cte, ctx);
225	                    if else_block.is_some() {
226	                        ctx.body.push_str(" else ");
227	                        else_block.clone().unwrap().to_c(cte, ctx);
228	                    }
229	                } else {
230	                    error(
231	                        if_cond.get_span(),
232	                        "EXPRESSION IF STATEMENTS NOT IMPLEMENTED",
233	                        "transpiling",
234	                    );
235	                }
236	
237	                let else_type = if let Some(ty) = else_block {
238	                    ty.get_type(cte)
239	                } else {
240	                    nil_type()
241	                };
242	                if if_block.get_type(cte) != else_type {
243	                    error(
244	                        if_block.get_span(),
245	                        "if and else blocks had different types",
246	                        "transpiling",
247	                    );
248	                }
249	
250	                false
251	            }
252	
253	            Expr::StmtBlockWithScope(exprs, span) => {
254	                cte.push_scope();
255	                ctx.body.push_str("{\n");
256	                Expr::StmtBlock(exprs.clone(), *span).to_c(cte, ctx);
257	                ctx.body.push('}');
258	                cte.pop_scope();
259	                false
260	            }
261	
262	            Expr::Print(expr, span) => {
263	                Expr::CallFunc(
264	                    "_print".into(),
265	                    vec![expr.get_type(cte)],
266	                    vec![expr.clone()],
267	                    *span,
268	                )
269	                .to_c(cte, ctx);
270	                true
271	            }
272	
273	            Expr::Discard(expr) => {
274	                expr.to_c(cte, ctx);
275	                true
276	            }
277	
278	            Expr::Variable(name, span) => {
279	                ctx.body.push_str(&cte.c_var_name(name, *span));
280	                false
281	            }
282	
283	            Expr::This(span) => {
284	                ctx.body.push(' ');
285	                ctx.body.push_str(&cte.c_var_name(cte.this(), *span));
286	                ctx.body.push(' ');
287	                false
288	            }
289	
290	            Expr::Declare(name, var_type, expr, is_mutable, span) => {
291	                let var_type = if var_type.is_some() {
292	                    cte.declare_var(name.clone(), *is_mutable, var_type.clone().unwrap());
293	                    var_type.clone().unwrap()
294	                } else {
295	                    let t = expr.clone().unwrap().get_type(cte);
296	                    cte.declare_var(name.clone(), *is_mutable, t.clone());
297	                    t
298	                };
299	
300	                ctx.body += format!(
301	                    "{} {}",
302	                    cte.c_type_name(&var_type, *span),
303	                    cte.c_var_name(&name, *span),
304	                )
305	                .as_str();
306	
307	                if expr.is_some() {
308	                    ctx.body.push('=');
309	                    expr.clone().unwrap().to_c(cte, ctx);
310	                }
311	                true
312	            }
313	
314	            Expr::CallFunc(name, gens, exprs, span) => {
315	                if !cte.var_exists(name) {
316	                    error(
317	                        *span,
318	                        &format!("Function '{}' does not exist", name),
319	                        "transpiling",
320	                    );
321	                }
322	                ctx.body
323	                    .push_str(format!("{}(", cte.c_func_instance_name(name, gens, *span)).as_str());
324	                for expr in exprs.iter() {
325	                    // Check if this argument is a struct — if so, pass by pointer
326	                    let arg_type = expr.get_type(cte);
327	                    if cte.is_class(&arg_type) {
328	                        ctx.body.push_str("&");
329	                        expr.to_c(cte, ctx);
330	                    } else {
331	                        expr.to_c(cte, ctx);
332	                    }
333	                    ctx.body.push(',');
334	                }
335	                if exprs.len() >= 1 {
336	                    ctx.body.pop();
337	                }
338	
339	                ctx.body.push_str(")");
340	                true
341	            }
342	
343	            Expr::Stmt(expr) => {
344	                expr.to_c(cte, ctx);
345	                true
346	            }
347	
348	            Expr::DeclareFunction(name, block, return_type, args, _gens, span) => {
349	                let mut arg_types = vec![];
350	                for arg in args {
351	                    arg_types.push(arg.1.clone());
352	                }
353	
354	                // Push scope and declare parameters. Struct params use pointers in C.
355	                cte.push_scope();
356	                for arg in args {
357	                    if cte.is_class(&arg.1) {
358	                        cte.declare_var_with_pointer(arg.0.clone(), false, arg.1.clone());
359	                    } else {
360	                        cte.declare_var(arg.0.clone(), false, arg.1.clone());
361	                    }
362	                }
363	
364	                // Infer return type from return statements in the body.
365	                // Parameters are already declared in scope. We also need to declare
366	                // local variables from the body so they're resolvable.
367	                declare_locals_from_block(cte, block);
368	                let ret_type = block.returned_type(cte, *span);
369	                let return_type = if return_type.is_some() {
370	                    return_type.clone().unwrap()
371	                } else {
372	                    if let Some(ty) = ret_type.clone() {
373	                        ty
374	                    } else {
375	                        nil_type()
376	                    }
377	                };
378	
379	                ctx.body.push_str(
380	                    format!(
381	                        "{} {}(",
382	                        cte.c_type_name(&return_type, *span),
383	                        cte.c_func_instance_name(&name, &[], *span),
384	                    )
385	                    .as_str(),
386	                );
387	
388	                for arg in args {
389	                    ctx.body.push_str(&cte.c_param_type(&arg.1, *span));
390	                    ctx.body.push(' ');
391	                    ctx.body.push_str(&cte.c_var_name(&arg.0, *span));
392	                    ctx.body.push_str(", ");
393	                }
394	                if ctx.body.ends_with(", ") {
395	                    ctx.body.pop();
396	                    ctx.body.pop();
397	                }
398	
399	                ctx.body.push(')');
400	
401	                block.to_c(cte, ctx);
402	
403	                cte.pop_scope();
404	
405	                false
406	            }
407	
408	            Expr::Assign(left, right, span) => {
409	                match left.as_ref() {
410	                    Expr::Variable(name, _) => {
411	                        cte.push_this(name);
412	                        ctx.body.push_str(&cte.c_var_name(name, *span));
413	                        ctx.body.push('=');
414	                        right.to_c(cte, ctx);
415	                        cte.pop_this();
416	                    }
417	                    Expr::Member(var, member, span) => {
418	                        let var_type = cte.get_var(var)
419	                            .unwrap_or_else(|| {
420	                                error(
421	                                    *span,
422	                                    &format!("Could not find variable '{}'", var),
423	                                    "transpiling",
424	                                );
425	                                (false, nil_type())
426	                            });
427	                        ctx.body.push_str(&cte.c_var_name(var, *span));
428	                        if cte.is_var_pointer(var) {
429	                            ctx.body.push_str("->");
430	                        } else {
431	                            ctx.body.push('.');
432	                        }
433	                        ctx.body.push_str(
434	                            &cte.c_member_name(&var_type.1, member, *span),
435	                        );
436	                        ctx.body.push('=');
437	                        right.to_c(cte, ctx);
438	                    }
439	                    _ => {
440	                        error(*span, "Invalid assignment target", "transpiler");
441	                    }
442	                }
443	                true
444	            }
445	
446	            Expr::Return(expr, _span) => {
447	                ctx.body.push_str("return ");
448	                expr.to_c(cte, ctx);
449	                true
450	            }
451	
452	            Expr::Delete(name) => {
453	                cte.del_var(name);
454	                false
455	            }
456	
457	            Expr::Nothing() => false,
458	
459	            Expr::While(cond, block) => {
460	                ctx.body.push_str("while (");
461	                cond.to_c(cte, ctx);
462	                ctx.body.push_str("){\n");
463	                block.to_c(cte, ctx);
464	                ctx.body.push_str("}");
465	                false
466	            }
467	
468	            Expr::Input(name) => {
469	                ctx.body.push_str("scanf(\"%d\",&");
470	                ctx.body.push_str(&cte.c_var_name(name, Span::empty()));
471	                ctx.body.push_str(")");
472	                true
473	            }
474	
475	            Expr::Use { .. } => false,
476	
477	            Expr::Class(ty, members, span) => {
478	                let c_type_name = cte.c_type_name(ty, *span);
479	                ctx.types.push_str("struct ");
480	                ctx.types.push_str(&c_type_name);
481	                ctx.types.push_str(" {\n");
482	                for member in members {
483	                    ctx.types.push_str(&cte.c_type_name(&member.1, *span));
484	                    ctx.types.push(' ');
485	                    ctx.types.push_str(&cte.c_member_name(ty, &member.0, *span));
486	                    ctx.types.push_str("; \n");
487	                }
488	                if ctx.types.ends_with("; \n") {
489	                    ctx.types.pop();
490	                    ctx.types.pop();
491	                    ctx.types.push('\n');
492	                }
493	                ctx.types.push_str("};\n");
494	
495	                true
496	            }
497	
498	            Expr::Member(var_name, member, span) => {
499	                let var = cte.get_var(var_name);
500	                if var.is_none() {
501	                    error(
502	                        *span,
503	                        &format!("Variable '{}' not defined", var_name),
504	                        "type checker",
505	                    );
506	                }
507	                let var_info = var.unwrap();
508	                ctx.body.push_str(&cte.c_var_name(var_name, *span));
509	
510	                if cte.is_var_pointer(var_name) {
511	                    ctx.body.push_str("->");
512	                } else {
513	                    ctx.body.push('.');
514	                }
515	
516	                ctx.body
517	                    .push_str(&cte.c_member_name(&var_info.1, member, *span));
518	                false
519	            }
520	
521	            _ => panic!("unexpected expression (for transpilation) '{:?}'", self),
522	        }
523	    }
