525	    pub fn pre_transpile(
526	        &self,
527	        cte: &mut CompileTimeEnv,
528	        ctx: &mut CodeGenContext,
529	        programs_to_transpile: &mut HashMap<String, bool>,
530	        current_file_dir: &str,
531	    ) {
532	        match self {
533	            Expr::DeclareFunction(name, block, return_type, args, _gens, span) => {
534	                if cte.get_var(name).is_some() {
535	                    error(
536	                    *span,
537	                    format!(
538	                        "Variable '{}' already exists and is immutable, could not declare function",
539	                        name
540	                    )
541	                        .as_str(),"pre-transpiling"
542	                );
543	                }
544	                let mut arg_types = vec![];
545	                for arg in args {
546	                    arg_types.push(arg.1.clone());
547	                }
548	
549	                // Push scope and declare parameters.
550	                cte.push_scope();
551	                for arg in args {
552	                    cte.declare_var(arg.0.clone(), false, arg.1.clone());
553	                }
554	
555	                // Process the body first so local variable declarations (like #x = ...)
556	                // are registered in the scope. This makes them visible to returned_type()
557	                // and get_type() calls that resolve variable names.
558	                block.pre_transpile(cte, ctx, programs_to_transpile, current_file_dir);
559	
560	                let ret_type = block.returned_type(cte, *span);
561	                let return_type = if return_type.is_some() {
562	                    return_type.clone().unwrap()
563	                } else {
564	                    if let Some(ty) = ret_type.clone() {
565	                        ty
566	                    } else {
567	                        nil_type()
568	                    }
569	                };
570	
571	                cte.add_func_type(return_type.clone(), arg_types.clone(), ctx, *span);
572	                // Declare the variable first so c_func_instance_name can find it
573	                cte.declare_global_var(
574	                    name.clone(),
575	                    false,
576	                    Type::with_generics("func", {
577	                        arg_types.push(return_type.clone());
578	                        let output = arg_types;
579	                        output
580	                    }),
581	                );
582	
583	                ctx.declarations.push_str(
584	                    format!(
585	                        "{} {}(",
586	                        cte.c_type_name(&return_type, *span),
587	                        cte.c_func_instance_name(&name, &[], *span),
588	                    )
589	                    .as_str(),
590	                );
591	
592	                for arg in args {
593	                    ctx.declarations.push_str(&cte.c_param_type(&arg.1, *span));
594	                    ctx.declarations.push(' ');
595	                    ctx.declarations.push_str(&cte.c_var_name(&arg.0, *span));
596	                    ctx.declarations.push_str(", ");
597	                }
598	                if ctx.declarations.ends_with(", ") {
599	                    ctx.declarations.pop();
600	                    ctx.declarations.pop();
601	                }
602	
603	                ctx.declarations.push_str(");\n");
604	
605	                cte.pop_scope();
606	            }
607	            Expr::Use { kind, path, span } => {
608	                let full_path = match kind {
609	                    UseKind::Std => format!("{}{}", STD_PATH, path),
610	                    UseKind::Normal => {
611	                        if current_file_dir.is_empty() {
612	                            path.to_string()
613	                        } else {
614	                            format!("{}/{}", current_file_dir, path)
615	                        }
616	                    }
617	                };
618	
619	                if !Path::new(&full_path).exists() {
620	                    error(*span, "File does not exist!", "pre-transpiling");
621	                    return;
622	                }
623	
624	                if !programs_to_transpile.contains_key(&full_path) {
625	                    programs_to_transpile.insert(full_path.clone(), true);
626	                    // Process this file immediately so its functions are available to subsequent
627	                    // declarations in the current file
628	                    let source = std::fs::read_to_string(&full_path)
629	                        .unwrap_or_else(|_| panic!("Failed to read {}", full_path));
630	                    let imported_ast = {
631	                        let mut scanner = crate::scanner::Scanner::new(source.clone());
632	                        let tokens = scanner.scan_tokens();
633	                        let mut parser = crate::parser::Parser::new(tokens);
634	                        parser.parse()
635	                    };
636	                    let imported_dir = std::path::Path::new(&full_path)
637	                        .parent()
638	                        .map(|p| p.to_string_lossy().to_string())
639	                        .unwrap_or_default();
640	                    imported_ast.pre_transpile(cte, ctx, programs_to_transpile, &imported_dir);
641	                }
642	            }
643	
644	            Expr::StmtBlock(exprs, _) | Expr::StmtBlockWithScope(exprs, _) => {
645	                for expr in exprs {
646	                    expr.pre_transpile(cte, ctx, programs_to_transpile, current_file_dir);
647	                }
648	            }
649	
650	            Expr::Discard(expr) => expr.pre_transpile(cte, ctx, programs_to_transpile, current_file_dir),
651	
652	            Expr::Class(ty, members, span) => {
653	                cte.register_class(ty.clone());
654	
655	                for member in members {
656	                    cte.declare_member(member.0.clone(), member.1.clone(), ty.clone());
657	                }
658	
659	                let c_type_name = cte.c_type_name(ty, *span);
660	                ctx.include.push_str("struct ");
661	                ctx.include.push_str(&c_type_name);
662	                ctx.include.push_str(";\n");
663	
664	                ctx.types.push_str("\ntypedef struct ");
665	                ctx.types.push_str(&c_type_name);
666	                ctx.types.push(' ');
667	                ctx.types.push_str(&c_type_name);
668	                ctx.types.push_str(";\n");
669	            }
670	
671	            Expr::Declare(name, var_type, expr, is_mutable, _span) => {
672	                if let Some(var_type) = var_type {
673	                    cte.declare_var(name.clone(), *is_mutable, var_type.clone());
674	                } else if let Some(expr_box) = expr {
675	                    let t = expr_box.get_type(cte);
676	                    cte.declare_var(name.clone(), *is_mutable, t);
677	                }
678	                if let Some(expr_box) = expr {
679	                    expr_box.pre_transpile(cte, ctx, programs_to_transpile, current_file_dir);
680	                }
681	            }
682	
683	            _ => {}
684	        }
685	    }
686	
687	    fn get_type(&self, cte: &CompileTimeEnv) -> Type {
688	        match self {
689	            Expr::Int(_) => "i32".into(),
690	            Expr::Float(_) => "f64".into(),
691	            Expr::Str(_) => "strlit".into(),
692	            Expr::Bool(_)
693	            | Expr::EqualEqual(..)
694	            | Expr::BangEqual(..)
695	            | Expr::Less(..)
696	            | Expr::LessEqual(..)
697	            | Expr::Greater(..)
698	            | Expr::GreaterEqual(..) => "bool".into(),
699	            Expr::Char(_) => "char".into(),
700	            Expr::Add(l, _, _)
701	            | Expr::Sub(l, ..)
702	            | Expr::Mult(l, ..)
703	            | Expr::Power(l, ..)
704	            | Expr::Div(l, ..) => l.get_type(cte),
705	            Expr::Return(_, _span) => nil_type(),
706	            Expr::CallFunc(name, _, _, span) => {
707	                let function = cte
708	                    .get_var(name)
709	                    .unwrap_or_else(|| {
710	                        error(
711	                            *span,
712	                            &format!("Function not defined: {}", name),
713	                            "type checker",
714	                        );
715	                        (false, nil_type())
716	                    })
717	                    .1;
718	                function.generics()[0].clone()
719	            }
720	            Expr::StmtBlock(exprs, _span) => exprs.last().unwrap().get_type(cte),
721	            Expr::StmtBlockWithScope(exprs, _span) => exprs.last().unwrap().get_type(cte),
722	            Expr::Variable(name, span) => {
723	                cte.get_var(name)
724	                    .unwrap_or_else(|| {
725	                        error(
726	                            *span,
727	                            &format!("Variable not defined: {}", name),
728	                            "type checker",
729	                        );
730	                        (false, nil_type())
731	                    })
732	                    .1
733	            }
734	            Expr::Discard(..) => nil_type(),
735	            Expr::Print(expr, _) => expr.get_type(cte),
736	            Expr::If(_, block, ..) => block.get_type(cte),
737	            Expr::Member(variable, member_name, span) => {
738	                let var = cte.get_var(variable);
739	                if var.is_none() {
740	                    error(
741	                        *span,
742	                        &format!("Variable '{}' not defined", variable),
743	                        "type checker",
744	                    );
745	                }
746	                let variable = var.unwrap();
747	                let var_type = variable.1;
748	
749	                let member = cte.get_member_type(&var_type, member_name);
750	
751	                let member_type = if member.is_none() {
752	                    error(
753	                        *span,
754	                        &format!(
755	                            "Member '{}' not defined for type '{}'",
756	                            member_name, var_type
757	                        ),
758	                        "type checker",
759	                    );
760	                    nil_type()
761	                } else {
762	                    member.unwrap()
763	                };
764	
765	                member_type
766	            }
767	            _ => panic!("unexpected expression (for type check) '{:?}'", self),
768	        }
769	    }
770	
771	    fn returned_type(&self, cte: &CompileTimeEnv, span: Span) -> Option<Type> {
772	        match self {
773	            Expr::Return(expr, _span) => Some(expr.get_type(cte)),
774	            Expr::Discard(expr) => expr.returned_type(cte, span),
775	            Expr::StmtBlock(exprs, span) => {
776	                let mut return_type = None;
777	                for expr in exprs {
778	                    let ret_type = expr.returned_type(cte, *span);
779	                    if let Some(returned_type) = ret_type {
780	                        if let Some(expected_type) = return_type.clone() {
781	                            if expected_type != returned_type {
782	                                error(
783	                                    {
784	                                        let expr_span = expr.get_span();
785	                                        if expr_span == Span::empty() {
786	                                            *span
787	                                        } else {
788	                                            expr_span
789	                                        }
790	                                    },
791	                                    "Returned type was different to previous returned type",
792	                                    "returned type checker",
793	                                );
794	                            }
795	                        } else {
796	                            return_type = Some(returned_type);
797	                        }
798	                    }
799	                }
800	                return_type
801	            }
802	            Expr::StmtBlockWithScope(exprs, span) => {
803	                Expr::StmtBlock(exprs.clone(), *span).returned_type(cte, *span)
804	            }
805	            _ => None,
806	        }
807	    }
808	
809	    fn get_span(&self) -> Span {
810	        match self {
811	            Expr::Add(_, _, span)
812	            | Expr::Sub(_, _, span)
813	            | Expr::Mult(_, _, span)
814	            | Expr::Div(_, _, span)
815	            | Expr::Power(_, _, span)
816	            | Expr::Mod(_, _, span)
817	            | Expr::BangEqual(_, _, span)
818	            | Expr::EqualEqual(_, _, span)
819	            | Expr::GreaterEqual(_, _, span)
820	            | Expr::LessEqual(_, _, span)
821	            | Expr::Less(_, _, span)
822	            | Expr::Greater(_, _, span)
823	            | Expr::Return(_, span) => *span,
824	            _ => Span::empty(),
825	        }
826	    }
827	}
