381	    fn resolve_var(&self, name: &str) -> Option<(usize, usize)> {
382	        for (idx, scope) in self.scopes.iter().enumerate().rev() {
383	            if let Some(id) = scope.get(name) {
384	                return Some((id.0, idx));
385	            }
386	        }
387	        None
388	    }
