391	    pub fn is_var_pointer(&self, name: &str) -> bool {
392	        for scope in self.scopes.iter().rev() {
393	            if let Some(entry) = scope.get(name) {
394	                return entry.3;
395	            }
396	        }
397	        false
398	    }
