400	    pub fn get_var(&self, name: &str) -> Option<(bool, Type)> {
401	        for scope in self.scopes.iter().rev() {
402	            if let Some((_id, is_mutable, var_type, _ptr)) = scope.get(name) {
403	                return Some((*is_mutable, var_type.clone()));
404	            }
405	        }
406	        None
407	    }
