418	    /// Returns the C variable name for variables.\
419	    /// Format: v_{id}s_{scope}
420	    pub fn c_var_name(&self, name: &str, span: Span) -> String {
421	        let (id, scope) = self.resolve_var(name).unwrap_or_else(|| {
422	            error(
423	                span,
424	                format!("Could not find variable '{}'", name).as_str(),
425	                "fetching variable name",
426	            );
427	            (0, 0)
428	        });
429	        format!("v_{}s_{}", id, scope)
430	    }
