432	    /// Returns the C variable name for a function instance with generics.\
433	    /// Format: v_{id}s_{scope}C{generic_types}D for generic functions, v_{id}s_{scope}CD for non-generic
434	    pub fn c_func_instance_name(&mut self, name: &str, generics: &[Type], span: Span) -> String {
435	        let (id, scope) = self.resolve_var(name).unwrap_or_else(|| {
436	            error(
437	                span,
438	                format!("Could not find variable '{}'", name).as_str(),
439	                "fetching function name",
440	            );
441	            (0, 0)
442	        });
443	
444	        let mut result = format!("v_{}s_{}", id, scope);
445	
446	        if generics.is_empty() {
447	            // Non-generic function: add CD suffix
448	            result.push_str("CD");
449	        } else {
450	            // Generic function: add C{generics}D
451	            result.push('C');
452	            for (i, g) in generics.iter().enumerate() {
453	                result.push_str(&self.c_type_name(g, span));
454	                if i != generics.len() - 1 {
455	                    result.push('_');
456	                }
457	            }
458	            result.push('D');
459	        }
460	
461	        result
462	    }
463	
464	    // Type Handling
465	
466	    pub fn register_type(&mut self, ty: Type) -> usize {
467	        if let Type::Conceptual(name) = &ty {
468	            panic!("Tried to register conceptual type: {}", name);
469	        }
470	
471	        let canonical_ty = self.canonicalize_type(ty);
472	
473	        if let Some(index) = self.all_types.iter().position(|t| t == &canonical_ty) {
474	            return index;
475	        }
476	
